    pub data: &'static [u16],
    pub heteronym: &'static [u16],
}

static CHAR_BLOCKS: &[CharBlock] = &[];
static PINYIN_DATA: &[PinyinData] = &[];
static HETERONYM_TABLE: &[&[u16]] = &[];

fn get_block_and_index(_ch: char) -> Option<(&'static CharBlock, usize)> {
    None
}

pub struct PinyinMulti {
    first: &'static PinyinData,
    other_indexes: &'static [u16],
}

impl IntoIterator for PinyinMulti {
    type Item = Pinyin;
    type IntoIter = PinyinMultiIter;
    fn into_iter(self) -> PinyinMultiIter {
        PinyinMultiIter { inner: self, index: 0 }
    }
}

pub struct PinyinMultiIter {
    inner: PinyinMulti,
    index: usize,
}

impl Iterator for PinyinMultiIter {
    type Item = Pinyin;
    fn next(&mut self) -> Option<Pinyin> {
        if self.index == 0 {
            self.index += 1;
            return Some(Pinyin(self.inner.first));
        }
        let idx = self.index - 1;
        if idx < self.inner.other_indexes.len() {
            self.index += 1;
            let data_idx = self.inner.other_indexes[idx] as usize;
            Some(Pinyin(&PINYIN_DATA[data_idx]))
        } else {
            None
        }
    }
}

pub trait ToPinyinMulti {
    type Output;
    fn to_pinyin_multi(&self) -> Self::Output;
}

impl ToPinyinMulti for char {
    type Output = Option<PinyinMulti>;
    fn to_pinyin_multi(&self) -> Option<PinyinMulti> {
        get_block_and_index(*self).and_then(|(block, idx)| {
            let first_idx = usize::try_from(block.data[idx]).unwrap();
            if first_idx == 0 { return None; }
            let first = &PINYIN_DATA[first_idx];
            let hetero_idx = usize::try_from(block.heteronym[idx]).unwrap();
            let other = HETERONYM_TABLE[hetero_idx];
            Some(PinyinMulti { first, other_indexes: other })
        })
    }
}

