use petgraph::Graph;
use std::error::Error;
use std::path::PathBuf;

pub trait DependencyNode<T, E>
where
    T: PartialEq,
{
    fn id(&self) -> T;
    fn dependencies(&self) -> Result<Vec<T>, E>;
}

pub fn create_dependency_graph<T, I, E>(
    nodes: Vec<T>,
) -> Result<Graph<T, ()>, CreateDependencyGraphError<I, E>>
where
    T: DependencyNode<I, E>,
    I: PartialEq,
    E: Error,
{
    let mut graph = Graph::new();
    for node in nodes {
        graph.add_node(node);
    }
    for idx in graph.node_indices() {
        let node = &graph[idx];
        let dependencies = node.dependencies().map_err(CreateDependencyGraphError::GetNodeDependenciesError)?;
        for dependency in dependencies {
            let dependency_idx = graph
                .node_indices()
                .find(|idx| graph[*idx].id() == dependency)
                .ok_or(CreateDependencyGraphError::MissingDependency(dependency))?;
            graph.add_edge(idx, dependency_idx, ());
        }
    }
    Ok(graph)
}

#[derive(thiserror::Error, Debug)]
pub enum CreateDependencyGraphError<I, E: Error> {
    #[error("Error while determining dependencies of a node: {0}")]
    GetNodeDependenciesError(#[source] E),
    #[error("Node references unknown dependency {0}")]
    MissingDependency(I),
}

pub struct BuildpackDependencyGraphNode {
    pub buildpack_id: String,
    pub path: PathBuf,
    pub dependencies: Vec<String>,
}

impl DependencyNode<String, std::convert::Infallible> for BuildpackDependencyGraphNode {
    fn id(&self) -> String {
        self.buildpack_id.clone()
    }
    fn dependencies(&self) -> Result<Vec<String>, std::convert::Infallible> {
        Ok(self.dependencies.clone())
    }
}

