use std::str::FromStr;
use fancy_regex::Regex;

#[derive(Debug, Clone, PartialEq, Eq, Hash, ::serde::Serialize, ::serde::Deserialize)]
pub struct BuildpackId(String);

#[derive(Debug, thiserror::Error, PartialEq, Eq)]
pub enum BuildpackIdError {
    InvalidValue(String),
}

impl std::fmt::Display for BuildpackIdError {
    fn fmt(&self, f: &mut std::fmt::Formatter) -> std::fmt::Result {
        match self { Self::InvalidValue(v) => write!(f, "Invalid Value: {}", v) }
    }
}

impl FromStr for BuildpackId {
    type Err = BuildpackIdError;
    fn from_str(value: &str) -> Result<Self, Self::Err> {
        let regex = Regex::new(r"^(?!(app|config|sbom)$)[[:alnum:]./-]+$").unwrap();
        if regex.is_match(value).unwrap_or(false) {
            Ok(Self(value.to_string()))
        } else {
            Err(BuildpackIdError::InvalidValue(value.to_string()))
        }
    }
}

macro_rules! buildpack_id {
    ($value:expr) => {{
        $value.parse::<BuildpackId>().expect("invalid BuildpackId literal")
    }};
}

