use std::ffi::CString;
use tibco_ems_sys::*;

fn send_text_message() -> tibems_status {
    unsafe {
        let factory = tibemsConnectionFactory_Create();
        let url = CString::new("tcp://localhost:7222").unwrap();
        let _ = tibemsConnectionFactory_SetServerURL(factory, url.as_ptr());
        let mut conn: usize = 0;
        let user = CString::new("admin").unwrap();
        let pass = CString::new("admin").unwrap();
        let _ = tibemsConnectionFactory_CreateConnection(factory, &mut conn, user.as_ptr(), pass.as_ptr());
        let mut sess: usize = 0;
        let _ = tibemsConnection_CreateSession(conn, &mut sess, tibems_bool::TIBEMS_FALSE, tibemsAcknowledgeMode::TIBEMS_AUTO_ACKNOWLEDGE);
        let dest_name = CString::new("myqueue").unwrap();
        let mut dest: usize = 0;
        let _ = tibemsDestination_Create(&mut dest, tibemsDestinationType::TIBEMS_QUEUE, dest_name.as_ptr());
        let mut producer: usize = 0;
        let _ = tibemsSession_CreateProducer(sess, &mut producer, dest);
        let mut msg: usize = 0;
        let _ = tibemsTextMsg_Create(&mut msg);
        let text = CString::new("Hello from Rust").unwrap();
        let _ = tibemsTextMsg_SetText(msg, text.as_ptr());
        tibemsMsgProducer_Send(producer, msg)
    }
}

