use std::cmp::Ordering;

pub trait Lattice: PartialOrd + Sized {
    fn meet_mut(&mut self, other: Self) -> bool;
    fn join_mut(&mut self, other: Self) -> bool;
    fn meet(self, other: Self) -> Self { let mut s = self; s.meet_mut(other); s }
    fn join(self, other: Self) -> Self { let mut s = self; s.join_mut(other); s }
}

pub trait BoundedLattice: Lattice {
    fn bottom() -> Self;
    fn top() -> Self;
}

#[derive(PartialEq, Eq, Clone, Copy, Debug, Hash)]
pub enum ConstPropagation<T> {
    Bottom,
    Constant(T),
    Top,
}

impl<T: PartialEq> PartialOrd for ConstPropagation<T> {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        use ConstPropagation::*;
        match (self, other) {
            (Bottom, Bottom) => Some(Ordering::Equal),
            (Bottom, _) => Some(Ordering::Less),
            (Constant(_), Bottom) => Some(Ordering::Greater),
            (Constant(x), Constant(y)) => if x == y { Some(Ordering::Equal) } else { None },
            (Constant(_), Top) => Some(Ordering::Less),
            (Top, Top) => Some(Ordering::Equal),
            (Top, _) => Some(Ordering::Greater),
        }
    }
}

impl<T: PartialEq> Lattice for ConstPropagation<T> {
    fn meet_mut(&mut self, other: Self) -> bool {
        use ConstPropagation::*;
        match (self, other) {
            (Bottom, _) => false,
            (Constant(x), Constant(y)) if x == &y => false,
            (this @ Constant(_), Bottom | Constant(_)) => { *this = Bottom; true },
            (_, Top) => false,
            (this @ Top, other) => { *this = other; true },
        }
    }
    fn join_mut(&mut self, other: Self) -> bool {
        use ConstPropagation::*;
        match (self, other) {
            (_, Bottom) => false,
            (this @ Bottom, other) => { *this = other; true },
            (Constant(x), Constant(y)) if x == &y => false,
            (this @ Constant(_), Constant(_) | Top) => { *this = Top; true },
            (Top, _) => false,
        }
    }
    fn meet(self, other: Self) -> Self {
        use ConstPropagation::*;
        match (self, other) {
            (Bottom, _) => Bottom,
            (Constant(_), Bottom) => Bottom,
            (Constant(x), Constant(y)) => if x == y { Constant(x) } else { Bottom },
            (Constant(x), Top) => Constant(x),
            (Top, other) => other,
        }
    }
    fn join(self, other: Self) -> Self {
        use ConstPropagation::*;
        match (self, other) {
            (Bottom, other) => other,
            (Constant(x), Bottom) => Constant(x),
            (Constant(x), Constant(y)) => if x == y { Constant(x) } else { Top },
            (Constant(_), Top) => Top,
            (Top, _) => Top,
        }
    }
}

impl<T: Lattice> BoundedLattice for ConstPropagation<T> where ConstPropagation<T>: Lattice {
    fn bottom() -> Self { ConstPropagation::Bottom }
    fn top() -> Self { ConstPropagation::Top }
}

