use std::fs;
use walrus::Module;

fn validate_chunks(main_path: &str, chunk_paths: &[&str]) -> Result<(), anyhow::Error> {
    let main_bytes = fs::read(main_path)?;
    let main_module = Module::from_buffer(&main_bytes)?;

    for &chunk_path in chunk_paths {
        let chunk_bytes = fs::read(chunk_path)?;
        let chunk_module = Module::from_buffer(&chunk_bytes)?;
        // Each chunk must contain exactly one funcref table
        assert_eq!(chunk_module.tables.iter().filter(|t| t.element_ty == walrus::RefType::Funcref).count(), 1);
        // Every import in the chunk should have a matching export in the main module
        for import in chunk_module.imports.iter() {
            let matching = main_module.exports.iter().find(|e| e.name == import.name);
            assert!(matching.is_some(), "missing export for import {}", import.name);
        }
    }
    Ok(())
}

