use std::cmp;

fn max_length(str1: &str, str2: &str) -> usize {
    if str1.len() > str2.len() { str1.len() } else { str2.len() }
}

fn get_common_chars(str1: &str, str2: &str, ordering: bool) -> Vec<char> {
    let mut common_chars = Vec::new();
    if str1.is_empty() || str2.is_empty() {
        return common_chars;
    }
    let max_len = max_length(str1, str2);
    let match_buffer = (max_len / 2).saturating_sub(1);
    let (f, s) = if ordering { (str2, str1) } else { (str1, str2) };
    for (i, c) in f.chars().enumerate() {
        let s_index = if i < match_buffer { 0 } else { i - match_buffer };
        let e_index = if s.len() <= i + match_buffer {
            s.len()
        } else {
            i + match_buffer + 1
        };
        let slice = &s[s_index..e_index];
        if slice.contains(c) {
            common_chars.push(c);
        }
    }
    common_chars
}

pub fn jaro_winkler_distance(str1: &str, str2: &str) -> f32 {
    let matches1 = get_common_chars(str1, str2, false);
    let matches2 = get_common_chars(str1, str2, true);
    if matches1.is_empty() || matches2.is_empty() || matches1.len() != matches2.len() {
        return 0.0;
    }
    let mut t = 0.0;
    for (a, b) in matches1.iter().zip(matches2.iter()) {
        if a != b {
            t += 0.5;
        }
    }
    let f1 = matches1.len() as f32 / str1.len() as f32;
    let f2 = matches2.len() as f32 / str2.len() as f32;
    let f3 = (matches1.len() as f32 - t) / matches1.len() as f32;
    (f1 + f2 + f3) / 3.0
}

