use tokenize::tokenize;

struct NGram<'a> {
    text: &'a str,
    n: usize,
    pad: &'a str,
}

impl<'a> NGram<'a> {
    fn calculate(&self) -> Vec<Vec<&'a str>> {
        let mut tokenized = tokenize(self.text);
        tokenized.shrink_to_fit();
        let count = tokenized.len().saturating_sub(self.n) + 1;
        let mut result = Vec::new();

        if !self.pad.is_empty() {
            for i in 1..self.n {
                let blanks = self.n - i;
                let mut seq = Vec::new();
                for _ in 0..blanks {
                    seq.push(self.pad);
                }
                let slice = &tokenized[0..self.n - blanks];
                seq.extend_from_slice(slice);
                result.push(seq);
            }
        }

        for i in 0..count {
            let slice = &tokenized[i..i + self.n];
            result.push(slice.to_vec());
        }

        if !self.pad.is_empty() {
            for blanks in 1..self.n {
                let keep = self.n - blanks;
                let start = tokenized.len() - keep;
                let mut seq = Vec::new();
                seq.extend_from_slice(&tokenized[start..]);
                for _ in 0..blanks {
                    seq.push(self.pad);
                }
                result.push(seq);
            }
        }

        result
    }
}

pub fn get_ngram<'a>(text: &'a str, n: usize) -> Vec<Vec<&'a str>> {
    let ng = NGram { text, n, pad: "" };
    ng.calculate()
}

pub fn get_ngram_with_padding<'a>(text: &'a str, n: usize, padding: &'a str) -> Vec<Vec<&'a str>> {
    let ng = NGram { text, n, pad: padding };
    ng.calculate()
}

