use std::collections::{HashMap, HashSet};
use tokenize::tokenize;
use std::borrow::Cow;
use rust_stemmers::{Algorithm, Stemmer};

#[derive(Debug, Clone, Default)]
pub struct TfIdf {
    doc_freqs: HashMap<String, usize>,
    term_freqs: HashMap<String, usize>,
    doc_count: usize,
    word_count: usize,
}

impl TfIdf {
    pub fn new() -> TfIdf {
        TfIdf {
            doc_freqs: HashMap::new(),
            term_freqs: HashMap::new(),
            doc_count: 0,
            word_count: 0,
        }
    }

    pub fn add(&mut self, corpus: &str) {
        let tokens = get_tokenized_and_stemmed(corpus);
        let mut seen = HashSet::new();
        for token in tokens {
            self.term_freqs.entry(token.to_string()).and_modify(|e| *e += 1).or_insert(1);
            self.word_count += 1;
            if seen.insert(token.clone()) {
                self.doc_freqs.entry(token.to_string()).and_modify(|e| *e += 1).or_insert(1);
            }
        }
        self.doc_count += 1;
    }

    fn tf(&self, term: &str) -> f32 {
        match self.term_freqs.get(term) {
            Some(freq) => *freq as f32 / self.word_count as f32,
            None => 0.0,
        }
    }

    fn idf(&self, term: &str) -> f32 {
        let doc_freq = match self.doc_freqs.get(term) {
            Some(freq) => *freq as f32,
            None => 0.0,
        };
        ((self.doc_count as f32) / (1.0 + doc_freq)).ln()
    }

    fn tf_idf(&self, term: &str) -> f32 {
        self.tf(term) * self.idf(term)
    }

    pub fn get(&self, terms: &str) -> f32 {
        let tokens = get_tokenized_and_stemmed(terms);
        let sum: f32 = tokens.iter().map(|t| self.tf_idf(t)).sum();
        sum / tokens.len() as f32
    }
}

fn get_tokenized_and_stemmed<'a>(text: &'a str) -> Vec<Cow<'a, str>> {
    let en_stemmer = Stemmer::create(Algorithm::English);
    tokenize(text).into_iter()
        .map(|t| en_stemmer.stem(t))
        .collect()
}

