pub struct SrgbaTuple(pub f32, pub f32, pub f32, pub f32);
impl core::str::FromStr for SrgbaTuple {
    type Err = ();
    fn from_str(s: &str) -> Result<Self, Self::Err> {
        if s.len() > 0 && s.as_bytes()[0] == b'#' {
            let digits = (s.len() - 1) / 3;
            if 1 + digits * 3 != s.len() { return Err(()); }
            if digits == 0 || digits > 4 { return Err(()); }
            let mut chars = s.chars().skip(1);
            macro_rules! digit {
                () => {{
                    let mut component = 0u16;
                    for _ in 0..digits {
                        component = component << 4;
                        let nybble = chars.next().unwrap().to_digit(16).ok_or(())? as u16;
                        component |= nybble;
                    }
                    (match digits {
                        1 => (component << 4) as f32,
                        2 => component as f32,
                        3 => (component >> 4) as f32,
                        4 => (component >> 8) as f32,
                        _ => return Err(()),
                    }) / 255.0
                }};
            }
            Ok(Self(digit!(), digit!(), digit!(), 1.0))
        } else {
            Err(())
        }
    }
}

