use std::fs;
use wasm_split_cli::{Splitter, OutputModules};

fn split_wasm() -> Result<(), anyhow::Error> {
    let original = fs::read("target/wasm32-unknown-unknown/release/app.wasm")?;
    let bindgened = fs::read("target/wasm32-unknown-unknown/release/app_bg.wasm")?;
    let splitter = Splitter::new(&original, &bindgened)?;
    let OutputModules { main, modules, chunks } = splitter.emit()?;

    // Write the main module
    fs::write("out/main.wasm", &main.bytes)?;
    // Write each split chunk
    for (i, chunk) in chunks.iter().enumerate() {
        let path = format!("out/chunk_{}_{}.wasm", i, chunk.module_name);
        fs::write(path, &chunk.bytes)?;
    }
    // Write each split module
    for (i, module) in modules.iter().enumerate() {
        let name = module.component_name.as_ref().unwrap();
        let path = format!("out/module_{}_{}.wasm", i, name);
        fs::write(path, &module.bytes)?;
    }
    Ok(())
}

