pub struct Config {
    pub appends: dark_std::sync::SyncVec<std::sync::Mutex<Box<dyn LogAppender>>>,
    pub level: log::LevelFilter,
    pub filters: dark_std::sync::SyncVec<Box<dyn fast_log::filter::Filter>>,
    pub format: Box<dyn fast_log::formats::RecordFormat>,
    pub chan_len: Option<usize>,
}

impl Config {
    pub fn new() -> Self { Self::default() }
    pub fn custom<Appender: LogAppender + 'static>(self, arg: Appender) -> Self {
        self.add_appender(arg)
    }
    pub fn add_appender<Appender: LogAppender + 'static>(mut self, arg: Appender) -> Self {
        self.appends.push(std::sync::Mutex::new(Box::new(arg)));
        self
    }
    pub fn chan_len(mut self, len: Option<usize>) -> Self { self.chan_len = len; self }
    pub fn console(self) -> Self {
        self.appends.push(std::sync::Mutex::new(Box::new(fast_log::plugin::console::ConsoleAppender {})));
        self
    }
}

impl Default for Config {
    fn default() -> Self {
        Self {
            appends: dark_std::sync::SyncVec::new(),
            level: log::LevelFilter::Trace,
            filters: dark_std::sync::SyncVec::new(),
            format: Box::new(fast_log::FastLogFormat::new()),
            chan_len: None,
        }
    }
}

