use std::fs::{File, create_dir_all, read_dir, remove_file};
use std::io::{self, Read, Write};
use std::path::{Path, PathBuf};
use std::hash::{Hash, Hasher};
use std::collections::hash_map;

fn hash_path<P: AsRef<Path>>(path: P) -> String {
    let mut hasher = hash_map::DefaultHasher::new();
    path.as_ref().hash(&mut hasher);
    format!("{:x}", hasher.finish())
}

fn user_forc_directory() -> PathBuf {
    std::env::temp_dir().join("forc")
}

pub struct PidFileLocking(PathBuf);

impl PidFileLocking {
    pub fn new<X: AsRef<Path>, Y: AsRef<Path>>(filename: X, dir: Y, extension: &str) -> Self {
        let _ = Self::cleanup_stale_files();
        let file_name = hash_path(filename);
        Self(
            user_forc_directory()
                .join(dir)
                .join(file_name)
                .with_extension(extension),
        )
    }
    pub fn lsp<X: AsRef<Path>>(filename: X) -> Self {
        Self::new(filename, ".lsp-locks", "lock")
    }
    #[cfg(not(target_os = "windows"))]
    fn is_pid_active(pid: usize) -> bool {
        use std::process::Command;
        let output = Command::new("ps").arg("-p").arg(pid.to_string()).output().expect("ps");
        let out = String::from_utf8_lossy(&output.stdout);
        out.contains(&format!("{} ", pid))
    }
    #[cfg(target_os = "windows")]
    fn is_pid_active(pid: usize) -> bool {
        use std::process::Command;
        let output = Command::new("tasklist").arg("/FI").arg(format!("PID eq {}", pid)).output().expect("tasklist");
        let out = String::from_utf8_lossy(&output.stdout);
        out.contains(&format!("{}", pid))
    }
    pub fn get_locker_pid(&self) -> Option<usize> {
        if let Ok(mut file) = File::open(&self.0) {
            let mut contents = String::new();
            file.read_to_string(&mut contents).ok()?;
            if let Ok(pid) = contents.trim().parse::<usize>() {
                if Self::is_pid_active(pid) {
                    return Some(pid);
                } else {
                    let _ = self.remove_file();
                }
            }
        }
        None
    }
    pub fn is_locked(&self) -> bool {
        self.get_locker_pid()
            .map(|pid| pid != std::process::id() as usize)
            .unwrap_or(false)
    }
    pub fn lock(&self) -> io::Result<()> {
        self.release()?;
        if let Some(dir) = self.0.parent() {
            create_dir_all(dir)?;
        }
        let mut fs = File::create(&self.0)?;
        fs.write_all(std::process::id().to_string().as_bytes())?;
        fs.sync_all()?;
        Ok(())
    }
    pub fn release(&self) -> io::Result<()> {
        if self.is_locked() {
            Err(io::Error::new(io::ErrorKind::Other, "locked by another process"))
        } else {
            self.remove_file()
        }
    }
    fn remove_file(&self) -> io::Result<()> {
        match remove_file(&self.0) {
            Err(e) if e.kind() != io::ErrorKind::NotFound => Err(e),
            _ => Ok(()),
        }
    }
    pub fn cleanup_stale_files() -> io::Result<Vec<PathBuf>> {
        Ok(vec![])
    }
}

pub fn is_file_dirty<X: AsRef<Path>>(path: X) -> bool {
    PidFileLocking::lsp(path.as_ref()).is_locked()
}

