use std::collections::HashMap;
use std::path::PathBuf;
use serde::{Deserialize, Serialize};
use bootspec::{BootspecError, SynthesizeError};

pub type Extensions = HashMap<String, serde_json::Value>;

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
pub struct BootJson {
    #[serde(flatten)]
    pub generation: Generation,
    #[serde(
        default = "HashMap::new",
        skip_serializing_if = "HashMap::is_empty",
        deserialize_with = "bootspec::deser::skip_generation_fields",
        flatten
    )]
    pub extensions: Extensions,
}

impl BootJson {
    pub fn synthesize_version(generation_path: &PathBuf, version: u64) -> Result<BootJson, BootspecError> {
        let generation = match version {
            v1::SCHEMA_VERSION => {
                let generation = v1::GenerationV1::synthesize(generation_path)?;
                Generation::V1(generation)
            }
            _ => return Err(BootspecError::Synthesize(SynthesizeError::UnsupportedVersion(version))),
        };
        Ok(BootJson { generation, extensions: HashMap::new() })
    }
}

