}

impl<T> Slab<T> {
    pub fn new() -> Self {
        Slab { entries: Vec::new(), len: 0, next: 0 }
    }

    pub fn insert(&mut self, val: T) -> usize {
        let key = self.next;
        self.len += 1;
        if key == self.entries.len() {
