pub struct LinearRgba(pub f32, pub f32, pub f32, pub f32);

impl SrgbaTuple {
    fn to_linear_component(v: f32) -> f32 {
        if v <= 0.04045 {
            v / 12.92
        } else {
            ((v + 0.055) / 1.055).powf(2.4)
        }
    }
    pub fn to_linear(self) -> LinearRgba {
        LinearRgba(
            Self::to_linear_component(self.0),
            Self::to_linear_component(self.1),
            Self::to_linear_component(self.2),
            self.3,
        )
    }
}

