pub fn i420_to_rgba(
    src_y: &[u8],
    stride_y: u32,
    src_u: &[u8],
    stride_u: u32,
    src_v: &[u8],
    stride_v: u32,
    dst_rgba: &mut [u8],
    dst_stride_rgba: u32,
    width: u32,
    height: u32,
    flip_y: bool,
) {
    assert::valid_420(src_y, stride_y, src_u, stride_u, src_v, stride_v, width, height);
    assert::valid_rgba(dst_rgba, dst_stride_rgba, width, height);

    let height = height as i32 * if flip_y { -1 } else { 1 };

    assert!(unsafe {
        yuv_sys::rs_I420ToRGBA(
            src_y.as_ptr(),
            stride_y as i32,
            src_u.as_ptr(),
            stride_u as i32,
            src_v.as_ptr(),
            stride_v as i32,
            dst_rgba.as_mut_ptr(),
            dst_stride_rgba as i32,
            width as i32,
            height,
        ) == 0
    });
}

