pub fn nv12_copy(
    src_y: &[u8],
    src_stride_y: u32,
    src_uv: &[u8],
    src_stride_uv: u32,
    dst_y: &mut [u8],
    dst_stride_y: u32,
    dst_uv: &mut [u8],
    dst_stride_uv: u32,
    width: u32,
    height: u32,
    flip_y: bool,
) {
    assert::valid_nv12(src_y, src_stride_y, src_uv, src_stride_uv, width, height);
    assert::valid_nv12(dst_y, dst_stride_y, dst_uv, dst_stride_uv, width, height);

    let height = height as i32 * if flip_y { -1 } else { 1 };

    assert!(unsafe {
        yuv_sys::rs_NV12Copy(
            src_y.as_ptr(),
            src_stride_y as i32,
            src_uv.as_ptr(),
            src_stride_uv as i32,
            dst_y.as_mut_ptr(),
            dst_stride_y as i32,
            dst_uv.as_mut_ptr(),
            dst_stride_uv as i32,
            width as i32,
            height,
        ) == 0
    });
}

