pub type TokenId = u32;

#[derive(Clone)]
pub struct SimpleVob {
    data: Vec<u32>,
    size: usize,
}

impl SimpleVob {
    pub fn alloc_with_capacity(size: usize, capacity: usize) -> Self {
        let mut data = Vec::with_capacity((capacity + 31) / 32);
        data.resize((capacity + 31) / 32, 0);
        Self { data, size }
    }

    pub fn allow_range(&mut self, range: std::ops::RangeInclusive<usize>) {
        let start = *range.start();
        let end = *range.end();
        if start > end { return; }
        let start_word = start / 32;
        let end_word = end / 32;
        let start_mask = !0u32 << (start % 32);
        let end_bit = end % 32;
        let end_mask = !0u32 >> (31 - end_bit);
        if start_word == end_word {
            self.data[start_word] |= start_mask & end_mask;
        } else {
            self.data[start_word] |= start_mask;
            for w in (start_word + 1)..end_word {
                self.data[w] = !0u32;
            }
            self.data[end_word] |= end_mask;
        }
    }
}

