impl<T> Arena<T> {
    pub unsafe fn alloc_uninitialized(&self, num: usize) -> &mut [MaybeUninit<T>] {
        let mut chunks = self.chunks.borrow_mut();
        if num > chunks.current.capacity() - chunks.current.len() {
            chunks.reserve(num);
        }
        let start = chunks.current.len();
        chunks.current.set_len(start + num);
        let ptr = chunks.current.as_mut_ptr().add(start) as *mut MaybeUninit<T>;
        unsafe { std::slice::from_raw_parts_mut(ptr, num) }
    }
}

