    pub fn new() -> Self { Section { endian: Endian::Little, contents: Cursor::new(vec![]), references: Vec::new() } }
    pub fn B64(&mut self, lbl: &Label) -> &mut Self {
        let offset = self.contents.get_ref().len();
        self.references.push((lbl.clone(), offset));
        // reserve space
        for _ in 0..8 { self.contents.write_u8(0).unwrap(); }
        self
    }
    pub fn get_contents(mut self) -> Option<Vec<u8>> {
        for (lbl, off) in self.references {
            let val = lbl.value()?;
            self.contents.set_position(off as u64);
            self.contents.write_u64::<BigEndian>(val).ok()?;
        }
        Some(self.contents.into_inner())
    }
}

