use oxc_cfg::{ControlFlowGraphBuilder, CtxCursor};
use oxc_syntax::node::NodeId;

let mut cfg = ControlFlowGraphBuilder::default();

// Attach an error harness for the whole function
cfg.attach_error_harness(oxc_cfg::ErrorEdgeKind::Implicit);

// Labeled block start (label "A")
let labeled = cfg.new_basic_block_normal();
cfg.ctx(Some("A")).default().allow_break().allow_continue();

// First loop inside the labeled block
let loop1 = cfg.new_basic_block_normal();
cfg.ctx(None).default().allow_break().allow_continue();
cfg.ctx(None).mark_break(loop1).mark_continue(loop1).resolve_with_upper_label();

// Second loop inside the labeled block
let loop2 = cfg.new_basic_block_normal();
cfg.ctx(None).default().allow_break().allow_continue();
cfg.ctx(None).mark_break(loop2).mark_continue(loop2).resolve_with_upper_label();

// Break out of the labeled block
cfg.append_break(NodeId::DUMMY, Some("A"));

// Resolve the labeled block and finish building
cfg.ctx(Some("A")).mark_break(labeled).resolve();
let control_flow_graph = cfg.build();

