extern crate alloc;
use alloc::vec::Vec;
use alloc::string::String;

pub struct Wtf8Buf {
    bytes: Vec<u8>,
}

impl Wtf8Buf {
    #[inline]
    pub fn from_str(s: &str) -> Wtf8Buf {
        Wtf8Buf { bytes: s.as_bytes().to_vec() }
    }

    #[inline]
    pub fn push(&mut self, cp: CodePoint) {
        // Very simplified: just encode as UTF-8 if not a surrogate, otherwise encode replacement char
        if (0xD800..=0xDFFF).contains(&cp.value) {
            self.bytes.extend_from_slice(&[0xEF, 0xBF, 0xBD]); // U+FFFD
        } else {
            let mut buf = [0u8; 4];
            let ch = unsafe { core::char::from_u32_unchecked(cp.value) };
            let encoded = ch.encode_utf8(&mut buf);
            self.bytes.extend_from_slice(encoded.as_bytes());
        }
    }

    #[inline]
    pub fn into_string_lossy(self) -> String {
        // In this stub we assume the internal bytes are already valid UTF-8 (surrogates replaced above)
        unsafe { String::from_utf8_unchecked(self.bytes) }
    }
}

pub struct CodePoint {
    pub value: u32,
}

impl CodePoint {
    #[inline]
    pub fn from_u32(value: u32) -> Option<CodePoint> {
        if value <= 0x10FFFF { Some(CodePoint { value }) } else { None }
    }
}

mod wtf8 {
    pub use super::{Wtf8Buf, CodePoint};
}

