pub struct VariableList<T, N> {
    vec: Vec<T>,
    _phantom: std::marker::PhantomData<N>,
}

impl<T, N> VariableList<T, N>
where
    N: typenum::Unsigned,
{
    pub fn new(vec: Vec<T>) -> Result<Self, ()> {
        if vec.len() <= N::to_usize() {
            Ok(VariableList { vec, _phantom: std::marker::PhantomData })
        } else {
            Err(())
        }
    }

    pub fn push(&mut self, value: T) -> Result<(), ()> {
        if self.vec.len() < N::to_usize() {
            self.vec.push(value);
            Ok(())
        } else {
            Err(())
        }
    }

    pub fn len(&self) -> usize {
        self.vec.len()
    }
}

impl<T, N> Default for VariableList<T, N>
where
    N: typenum::Unsigned,
{
    fn default() -> Self {
        VariableList {
            vec: Vec::new(),
            _phantom: std::marker::PhantomData,
        }
    }
}

