    NoFeature,
    SkipDownload,
    RpcUserAndPasswordUsed,
}

impl std::fmt::Display for Error {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Error::NoBitcoindExecutableFound => write!(f, "bitcoind executable not found"),
            Error::NoFeature => write!(f, "feature not enabled"),
            Error::SkipDownload => write!(f, "skip download"),
            Error::RpcUserAndPasswordUsed => write!(f, "rpcuser/rpcpassword not allowed"),
        }
    }
}
impl std::error::Error for Error {}

const INVALID_ARGS: [&str; 2] = ["-rpcuser", "-rpcpassword"];

pub fn validate_args(args: Vec<&str>) -> anyhow::Result<Vec<&str>> {
    for arg in &args {
        if INVALID_ARGS.iter().any(|x| arg.starts_with(x)) {
            return Err(anyhow::anyhow!(Error::RpcUserAndPasswordUsed));
        }
    }
    Ok(args)
}

