use std::sync::Arc;
use std::sync::atomic::{AtomicUsize, Ordering};
use std::cell::UnsafeCell;

struct Node<T> {
    sequence: AtomicUsize,
    value: Option<T>,
}

type CachelinePadding = [u8; 64];

struct State<T> {
    _pad0: CachelinePadding,
    buffer: Vec<UnsafeCell<Node<T>>>,
    mask: usize,
    _pad1: CachelinePadding,
    enqueue_pos: AtomicUsize,
    _pad2: CachelinePadding,
    dequeue_pos: AtomicUsize,
    _pad3: CachelinePadding,
}

pub struct ArrayQueue<T> {
    state: Arc<State<T>>,
}

impl<T: Send + 'static> ArrayQueue<T> {
    pub fn with_capacity(capacity: usize) -> ArrayQueue<T> {
        ArrayQueue { state: Arc::new(State::with_capacity(capacity)) }
    }
    pub fn push(&self, value: T) -> Result<(), T> {
        self.state.push(value)
    }
    pub fn pop(&self) -> Option<T> {
        self.state.pop()
    }
}

impl<T> State<T> {
    fn with_capacity(_capacity: usize) -> State<T> {
        State {
            _pad0: [0; 64],
            buffer: Vec::new(),
            mask: 0,
            _pad1: [0; 64],
            enqueue_pos: AtomicUsize::new(0),
            _pad2: [0; 64],
            dequeue_pos: AtomicUsize::new(0),
            _pad3: [0; 64],
        }
    }
    fn push(&self, _value: T) -> Result<(), T> { Err(_value) }
    fn pop(&self) -> Option<T> { None }
}

