use std::num::NonZeroU8;

#[derive(Copy, Clone, Debug, Eq, PartialEq, Ord, PartialOrd, Hash)]
pub enum Signal {
    Interrupt,
    Quit,
    Terminate,
    User1,
    User2,
}

pub struct SignalSet(NonZeroU8);

impl SignalSet {
    pub const fn all() -> SignalSet {
        SignalSet(unsafe { NonZeroU8::new_unchecked(1 | 2 | 4 | 8 | 16) })
    }
    pub fn contains<S>(self, other: S) -> bool
    where
        S: Into<SignalSet>,
    {
        let other = other.into();
        (self.0.get() & other.0.get()) == other.0.get()
    }
}

impl From<Signal> for SignalSet {
    fn from(signal: Signal) -> Self {
        SignalSet(unsafe {
            NonZeroU8::new_unchecked(match signal {
                Signal::Interrupt => 1,
                Signal::Quit => 2,
                Signal::Terminate => 4,
                Signal::User1 => 8,
                Signal::User2 => 16,
            })
        })
    }
}

