use std::sync::atomic::AtomicU64;
use std::sync::atomic::Ordering;

#[cfg(not(feature = "parallel"))]
type Word = u64;
#[cfg(feature = "parallel")]
type Word = AtomicU64;

pub struct BitVector {
    bits: u64,
    vector: Box<[Word]>,
}

impl BitVector {
    pub fn new(bits: u64) -> Self {
        let n = (bits + 63) / 64;
        let mut v = Vec::with_capacity(n as usize);
        for _ in 0..n {
            v.push(Word::default());
        }
        BitVector { bits, vector: v.into_boxed_slice() }
    }

    #[inline]
    pub fn insert_sync(&mut self, bit: u64) -> bool {
        let (word, mask) = word_mask(bit);
        #[cfg(feature = "parallel")]
        let data = self.vector[word].get_mut();
        #[cfg(not(feature = "parallel"))]
        let data = &mut self.vector[word];
        let old = *data;
        *data |= mask;
        old & mask == 0
    }

    #[inline]
    pub fn contains(&self, bit: u64) -> bool {
        let (word, mask) = word_mask(bit);
        (self.get_word(word) & mask) != 0
    }

    fn get_word(&self, word: usize) -> u64 {
        #[cfg(feature = "parallel")]
        return self.vector[word].load(Ordering::Relaxed) as u64;
        #[cfg(not(feature = "parallel"))]
        return self.vector[word] as u64;
    }
}

fn word_mask(index: u64) -> (usize, u64) {
    let word = (index / 64) as usize;
    let mask = 1 << (index % 64);
    (word, mask)
}

