use std::hash::Hash;
use std::fmt::Debug;
use std::borrow::Borrow;

pub struct BoomHashMap<K: Hash, D> {
    mphf: Mphf<K>,
    keys: Vec<K>,
    values: Vec<D>,
}

impl<K, D> BoomHashMap<K, D>
where
    K: Hash + Debug + PartialEq,
    D: Debug,
{
    pub fn new(keys: Vec<K>, data: Vec<D>) -> Self {
        let mphf = Mphf::new(1.7, &keys);
        BoomHashMap { mphf, keys, values: data }
    }

    pub fn get<Q: ?Sized>(&self, kmer: &Q) -> Option<&D>
    where
        K: Borrow<Q>,
        Q: Hash + Eq,
    {
        let maybe_pos = self.mphf.try_hash(kmer);
        match maybe_pos {
            Some(pos) => {
                let hashed = &self.keys[pos as usize];
                if kmer == hashed.borrow() {
                    Some(&self.values[pos as usize])
                } else {
                    None
                }
            }
            None => None,
        }
    }
}

pub struct Mphf<T> {
    _phantom: std::marker::PhantomData<T>,
}

impl<T: std::hash::Hash> Mphf<T> {
    pub fn new(_gamma: f64, _objects: &[T]) -> Self {
        Mphf { _phantom: std::marker::PhantomData }
    }
    pub fn try_hash<Q: ?Sized>(&self, _item: &Q) -> Option<u64>
    where
        T: Borrow<Q>,
        Q: Hash + Eq,
    {
        None
    }
}

