use std::ops::Range;
use crate::generators::{IndexedPolygon, SharedVertex};
use crate::{Quad, Vertex, Normal, Position};

pub struct Cube {
    range: Range<usize>,
}

impl Cube {
    pub fn new() -> Self {
        Cube { range: 0..6 }
    }

    fn vert(&self, idx: usize) -> Position {
        let x = if idx & 4 == 4 { 1.0 } else { -1.0 };
        let y = if idx & 2 == 2 { 1.0 } else { -1.0 };
        let z = if idx & 1 == 1 { 1.0 } else { -1.0 };
        [x, y, z].into()
    }

    fn face_indexed(&self, idx: usize) -> (Normal, Quad<usize>) {
        match idx {
            0 => ([1.0, 0.0, 0.0].into(), Quad::new(0b110, 0b111, 0b101, 0b100)),
            1 => ([-1.0, 0.0, 0.0].into(), Quad::new(0b000, 0b001, 0b011, 0b010)),
            2 => ([0.0, 1.0, 0.0].into(), Quad::new(0b011, 0b111, 0b110, 0b010)),
            3 => ([0.0, -1.0, 0.0].into(), Quad::new(0b100, 0b101, 0b001, 0b000)),
            4 => ([0.0, 0.0, 1.0].into(), Quad::new(0b101, 0b111, 0b011, 0b001)),
            5 => ([0.0, 0.0, -1.0].into(), Quad::new(0b000, 0b010, 0b110, 0b100)),
            _ => panic!("invalid face index"),
        }
    }

    fn face(&self, idx: usize) -> Quad<Vertex> {
        let (normal, quad) = self.face_indexed(idx);
        quad.map_vertex(|i| Vertex { pos: self.vert(i), normal })
    }
}

impl Default for Cube {
    fn default() -> Self {
        Self::new()
    }
}

impl Iterator for Cube {
    type Item = Quad<Vertex>;

    fn next(&mut self) -> Option<Quad<Vertex>> {
        self.range.next().map(|idx| self.face(idx))
    }

    fn size_hint(&self) -> (usize, Option<usize>) {
        self.range.size_hint()
    }
}

impl ExactSizeIterator for Cube {
    fn len(&self) -> usize {
        self.range.len()
    }
}

impl SharedVertex<Vertex> for Cube {
    fn shared_vertex(&self, idx: usize) -> Vertex {
        let (normal, quad) = self.face_indexed(idx / 4);
        let vid = match idx % 4 {
            0 => quad.x,
            1 => quad.y,
            2 => quad.z,
            3 => quad.w,
            _ => unreachable!(),
        };
        Vertex { pos: self.vert(vid), normal }
    }

    fn shared_vertex_count(&self) -> usize { 24 }
}

impl IndexedPolygon<Quad<usize>> for Cube {
    fn indexed_polygon(&self, idx: usize) -> Quad<usize> {
        Quad::new(idx * 4, idx * 4 + 1, idx * 4 + 2, idx * 4 + 3)
    }

    fn indexed_polygon_count(&self) -> usize { 6 }
}

