use dora_message::common::{NodeError, NodeErrorCause, NodeExitStatus};
use std::borrow::Cow;

fn handle_node_error(error: NodeError) {
    // Describe the cause
    match error.cause {
        NodeErrorCause::GraceDuration => {
            eprintln!("Node was killed due to grace period timeout");
        }
        NodeErrorCause::Cascading { caused_by_node } => {
            eprintln!("Node {caused_by_node} exited before connecting to Dora");
        }
        NodeErrorCause::FailedToSpawn(ref msg) => {
            eprintln!("Failed to spawn node: {msg}");
        }
        NodeErrorCause::Other { ref stderr } => {
            if !stderr.is_empty() {
                eprintln!("Node error stderr:\n{stderr}");
            }
        }
    }

    // Report the exit status
    match error.exit_status {
        NodeExitStatus::Success => {}
        NodeExitStatus::IoError(ref err) => {
            eprintln!("I/O error while reading exit status: {err}");
        }
        NodeExitStatus::ExitCode(code) => {
            eprintln!("Node exited with code {code}");
        }
        NodeExitStatus::Signal(sig) => {
            let sig_str: Cow<'static, str> = match sig {
                1 => "SIGHUP".into(),
                2 => "SIGINT".into(),
                3 => "SIGQUIT".into(),
                4 => "SIGILL".into(),
                6 => "SIGABRT".into(),
                8 => "SIGFPE".into(),
                9 => "SIGKILL".into(),
                11 => "SIGSEGV".into(),
                13 => "SIGPIPE".into(),
                14 => "SIGALRM".into(),
                15 => "SIGTERM".into(),
                other => other.to_string().into(),
            };
            eprintln!("Node terminated by signal {sig_str}");
        }
        NodeExitStatus::Unknown => {
            eprintln!("Node exit status unknown");
        }
    }
}

