pub enum IntegerBits {
    Eight,
    Sixteen,
    ThirtyTwo,
    SixtyFour,
    V256,
}

impl IntegerBits {
    pub fn would_overflow(&self, v: u64) -> bool {
        if v == 0 {
            return false;
        }
        let needed_bits = v.ilog2() + 1;
        let bits = match self {
            IntegerBits::Eight => 8,
            IntegerBits::Sixteen => 16,
            IntegerBits::ThirtyTwo => 32,
            IntegerBits::SixtyFour => 64,
            IntegerBits::V256 => return false,
        };
        needed_bits > bits
    }
}

