use std::sync::Arc;

#[derive(Clone)]
pub struct Source {
    text: Arc<str>,
    line_starts: Arc<Vec<usize>>,
}

impl Source {
    pub fn new(text: &str) -> Self {
        let line_starts = {
            let mut v = vec![0];
            for (idx, c) in text.char_indices() {
                if c == '\n' {
                    v.push(idx + c.len_utf8());
                }
            }
            Arc::new(v)
        };
        Source {
            text: Arc::from(text),
            line_starts,
        }
    }

    pub fn line_col_one_index(&self, position: usize) -> LineCol {
        let (line, line_start) = match self.line_starts.binary_search(&position) {
            Ok(line) => (line, self.line_starts.get(line)),
            Err(0) => (0, None),
            Err(line) => (line - 1, self.line_starts.get(line - 1)),
        };
        line_start.map_or(LineCol { line: 1, col: 1 }, |ls| LineCol {
            line: line + 1,
            col: position - ls + 1,
        })
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub struct LineCol {
    pub line: usize,
    pub col: usize,
}

pub struct Span {
    src: Source,
    start: usize,
    end: usize,
}

impl Span {
    pub fn from_string(source: String) -> Self {
        let len = source.len();
        Span {
            src: Source::new(&source),
            start: 0,
            end: len,
        }
    }

    pub fn start_line_col_one_index(&self) -> LineCol {
        self.src.line_col_one_index(self.start)
    }
}

