impl<C> Load<C, SimpleKey> for Foo {
    type Error = std::io::Error;

    fn load(
        key: SimpleKey,
        _storage: &mut Storage<C, SimpleKey>,
        _: &mut C,
    ) -> Result<Loaded<Self, SimpleKey>, Self::Error> {
        let path = match key {
            SimpleKey::Path(p) => p,
            _ => return Err(std::io::Error::new(std::io::ErrorKind::Other, "expected path key")),
        };
        let mut file = File::open(path)?;
        let mut contents = String::new();
        file.read_to_string(&mut contents)?;
        Ok(Loaded::without_dep(Foo(contents)))
    }
}

impl<C> Load<C, SimpleKey> for Bar {
    type Error = std::io::Error;

    fn load(
        _key: SimpleKey,
        storage: &mut Storage<C, SimpleKey>,
        ctx: &mut C,
    ) -> Result<Loaded<Self, SimpleKey>, Self::Error> {
        let foo_key = SimpleKey::from_path("foo.txt");
        let foo_res: Res<Foo> = storage.get(&foo_key, ctx).expect("Foo must exist");
        let bar_content = format!("Bar sees: {}", foo_res.borrow().0);
        Ok(Loaded::with_deps(Bar(bar_content), vec![foo_key]))
    }
}

