    pub port: NonZeroU16,
    pub database: String,
    pub username: String,
    pub password: String,
}

impl From<Credentials> for postgres::Config {
    fn from(value: Credentials) -> Self {
        let mut config = Self::new();
        config
            .host(&value.hostname)
            .port(value.port.get())
            .dbname(&value.database)
            .user(&value.username)
            .password(&value.password);
        config
    }
}

