fn ip2long(ip: &str) -> Result<u128> {
    // Very simplified parser that only handles the all‑zero address for the example
    if ip == "::" { Ok(0) } else { Err(error::Error::V6IP()) }
}

fn long2ip(long_ip: u128, _rfc1924: bool) -> String {
    if long_ip == 0 { "::".to_string() } else { "::1".to_string() }
}

pub fn cidr2block(cidr: &str) -> Result<(String, String)> {
    if !cidr.contains('/') { return Err(error::Error::V6CIDR()); }
    let parts: Vec<&str> = cidr.split('/').collect();
    let ip_part = parts[0];
    let prefix: u128 = parts[1].parse().map_err(|_| error::Error::V6CIDR())?;
    let ip_long = ip2long(ip_part)?;
    let shift = 128 - prefix as u32;
    let start = ip_long.checked_shr(shift).unwrap_or(0).checked_shl(shift).unwrap_or(0);
    let mask = if prefix == 0 { u128::MAX } else { (1u128 << shift) - 1 };
    let end = start | mask;
    Ok((long2ip(start, false), long2ip(end, false)))
}

