#[derive(Debug, Clone)]
pub struct IpRange<T> { ip_range: T }

impl Iterator for IpRange<IPv4> {
    type Item = String;
    fn next(&mut self) -> Option<Self::Item> {
        if self.ip_range.iter_ip >= self.ip_range.end_ip { return None; }
        self.ip_range.iter_ip += 1;
        Some(format!("{}.{}.{}.{}",
            (self.ip_range.iter_ip >> 24) & 0xFF,
            (self.ip_range.iter_ip >> 16) & 0xFF,
            (self.ip_range.iter_ip >> 8) & 0xFF,
            self.ip_range.iter_ip & 0xFF))
    }
}

impl IpRange<IPv4> {
    pub fn new(start: &str, end: &str) -> Result<Self> {
        fn parse_ip(s: &str) -> Result<u32> {
            let parts: Vec<&str> = s.split('.').collect();
            if parts.len() != 4 { return Err(error::Error::V4IP()); }
            let mut val: u32 = 0;
            for p in parts {
                let oct: u32 = p.parse().map_err(|_| error::Error::V4IP())?;
                val = (val << 8) | oct;
            }
            Ok(val)
        }
        let start_ip = parse_ip(start)?;
        let end_ip = if end.is_empty() { start_ip } else { parse_ip(end)? };
        if start_ip > end_ip { return Err(error::Error::V4Subnet()); }
        Ok(IpRange { ip_range: IPv4::new(start_ip, end_ip) })
    }
}

