use zeroize::Zeroize;
use std::borrow::{Borrow, BorrowMut};
use std::str::FromStr;
use std::fmt;
use std::mem;
use crate::secure_utils::memlock;

pub struct SecureVec<T>
where
    T: Copy + Zeroize,
{
    pub(crate) content: Vec<T>,
}

impl<T> SecureVec<T>
where
    T: Copy + Zeroize,
{
    pub fn new(mut cont: Vec<T>) -> Self {
        memlock::mlock(cont.as_mut_ptr(), cont.capacity());
        SecureVec { content: cont }
    }
    pub fn unsecure(&self) -> &[T] {
        self.content.borrow()
    }
    pub fn zero_out(&mut self) {
        self.content.zeroize();
    }
}

pub struct SecureString(SecureVec<u8>);

impl SecureString {
    pub fn into_unsecure(mut self) -> String {
        memlock::munlock(self.0.content.as_mut_ptr(), self.0.content.capacity());
        let content = mem::take(&mut self.0.content);
        mem::forget(self);
        unsafe { String::from_utf8_unchecked(content) }
    }
}

impl<T: Into<String>> From<T> for SecureString {
    fn from(s: T) -> SecureString {
        SecureString(SecureVec::new(s.into().into_bytes()))
    }
}

