mod icon {
    use mime::Mime;
    #[derive(Clone)]
    pub struct Icon {
        pub icon_name: String,
        pub mime_type: Mime,
    }
    pub fn find_icon(icons: &[Icon], mime_type: &Mime) -> Option<String> {
        for icon in icons {
            if icon.mime_type == *mime_type {
                return Some(icon.icon_name.clone());
            }
        }
        None
    }
}

pub struct SharedMimeInfo {
    icons: Vec<icon::Icon>,
    generic_icons: Vec<icon::Icon>,
    // other fields omitted
}

impl SharedMimeInfo {
    pub fn new() -> SharedMimeInfo {
        SharedMimeInfo { icons: Vec::new(), generic_icons: Vec::new() }
    }
    pub fn lookup_icon_names(&self, mime_type: &mime::Mime) -> Vec<String> {
        let mut res = Vec::new();
        if let Some(v) = icon::find_icon(&self.icons, mime_type) {
            res.push(v);
        }
        res.push(mime_type.essence_str().replace("/", "-"));
        match icon::find_icon(&self.generic_icons, mime_type) {
            Some(v) => res.push(v),
            None => {
                let generic = format!("{}-x-generic", mime_type.type_());
                res.push(generic);
            }
        }
        res
    }
}

