pub mod beusize {
    use std::ptr;
    use std::mem;

    #[inline]
    pub fn encode(dst: &mut [u8], src: u64, nbytes: usize) {
        assert_eq!(dst.len(), nbytes);
        assert!(nbytes > 0 && nbytes <= 8);
        unsafe {
            let bytes: [u8; 8] = mem::transmute::<_, [u8; 8]>(src.to_be());
            ptr::copy_nonoverlapping(
                (&bytes[8 - nbytes..]).as_ptr(),
                dst.as_mut_ptr(),
                nbytes,
            );
        }
    }

    #[inline]
    pub fn decode(src: &[u8], nbytes: usize) -> u64 {
        assert_eq!(src.len(), nbytes);
        assert!(nbytes > 0 && nbytes <= 8);
        let mut dst = [0u8; 8];
        unsafe {
            ptr::copy_nonoverlapping(
                src.as_ptr(),
                dst.as_mut_ptr().offset((8 - nbytes) as isize),
                nbytes,
            );
            (*(dst.as_ptr() as *const u64)).to_be()
        }
    }
}

