pub mod u8 {
    use std::ptr;
    use std::mem;

    pub const BYTES: usize = 1;

    #[inline]
    pub unsafe fn reverse_memory_inplace(buf: *mut u8, count: usize) {
        use std::ptr::swap;
        let n = count >> 1;
        let b = buf;
        for i in 0..n {
            swap(b.offset(i as isize), b.offset((count - 1 - i) as isize));
        }
    }

    #[inline]
    pub unsafe fn reverse_memory(dst: *mut u8, src: *const u8, count: usize) {
        let (mut d, mut s) = (dst, src);
        s = s.offset((count - 1) as isize);
        for _ in 0..count {
            *d = *s;
            d = d.offset(1);
            s = s.offset(-1);
        }
    }
}

