            }
            pub const fn is_local(&self) -> bool { (self.0[0] & 0b0000_0010) != 0 }
            pub fn set_multicast(&mut self, v: bool) {
                if v { self.0[0] |= 0b0000_0001; } else { self.0[0] &= !0b0000_0001; }
            }
