use opentelemetry::logs::{LogRecord, AnyValue};
use opentelemetry::Key;
use tracing::field::Visit;

struct EventVisitor<'a, LR: LogRecord> {
    log_record: &'a mut LR,
}

impl<'a, LR: LogRecord> Visit for EventVisitor<'a, LR> {
    fn record_debug(&mut self, field: &tracing::field::Field, value: &dyn std::fmt::Debug) {
        if field.name() == "message" {
            self.log_record.set_body(format!("{value:?}").into());
        } else {
            self.log_record.add_attribute(Key::new(field.name()), AnyValue::from(format!("{value:?}")));
        }
    }
}

