use std::path::Path;

pub fn find_up<FN: AsRef<str>>(from: &Path, filenames: &[FN]) -> Option<std::path::PathBuf> {
    let mut current = from.to_path_buf();
    loop {
        for filename in filenames {
            let path = current.join(filename.as_ref());
            if path.exists() {
                return Some(path);
            }
        }
        if !current.pop() {
            return None;
        }
    }
}

