fn apply_patch(diff: &str, old_content: &str) -> String {
    let diff = Patch::from_single(diff).unwrap();
    let mut out: Vec<&str> = Vec::new();
    let mut old_line: u64 = 0;

    for hunk in diff.hunks {
        while old_line < hunk.old_range.start - 1 {
            if let Some(line) = old_content.lines().nth(old_line as usize) {
                out.push(line);
            }
            old_line += 1;
        }
        for line in &hunk.lines {
            match line {
                patch::Line::Add(s) | patch::Line::Context(s) => out.push(s),
                _ => {}
            }
        }
    }
    out.join("\n")
}

