#[derive(FromDynamic, Debug, PartialEq)]
#[dynamic(try_from = "String")]
struct Size {
    width: u32,
    height: u32,
}

impl TryFrom<String> for Size {
    type Error = String;
    fn try_from(s: String) -> Result<Self, Self::Error> {
        let parts: Vec<&str> = s.split('x').collect();
        if parts.len() != 2 {
            return Err("expected format WIDTHxHEIGHT".to_string());
        }
        let width = parts[0].parse::<u32>().map_err(|e| e.to_string())?;
        let height = parts[1].parse::<u32>().map_err(|e| e.to_string())?;
        Ok(Size { width, height })
    }
}

