#[derive(Clone, Component, Copy, Debug, Reflect)]
pub struct FpsCameraController {
    pub enabled: bool,
    pub mouse_rotate_sensitivity: Vec2,
    pub translate_sensitivity: f32,
    pub smoothing_weight: f32,
}

impl Default for FpsCameraController {
    fn default() -> Self {
        Self { enabled: true, mouse_rotate_sensitivity: Vec2::splat(0.2), translate_sensitivity: 2.0, smoothing_weight: 0.9 }
    }
}

#[derive(Event)]
pub enum ControlEvent { Rotate(Vec2), TranslateEye(Vec3) }

fn on_controller_enabled_changed(mut smoothers: Query<(&mut Smoother, &FpsCameraController), Changed<FpsCameraController>>) {
    for (mut smoother, controller) in smoothers.iter_mut() {
        smoother.set_enabled(controller.enabled);
    }
}

fn default_input_map(mut events: EventWriter<ControlEvent>, keyboard: Res<ButtonInput<KeyCode>>, mut mouse_motion: EventReader<MouseMotion>, controllers: Query<&FpsCameraController>) {
    if let Some(controller) = controllers.iter().find(|c| c.enabled) {
        let mut delta = Vec2::ZERO;
        for ev in mouse_motion.read() { delta += ev.delta; }
        events.send(ControlEvent::Rotate(controller.mouse_rotate_sensitivity * delta));
        for (key, dir) in [(KeyCode::KeyW, Vec3::Z), (KeyCode::KeyA, Vec3::X), (KeyCode::KeyS, -Vec3::Z), (KeyCode::KeyD, -Vec3::X), (KeyCode::ShiftLeft, -Vec3::Y), (KeyCode::Space, Vec3::Y)].iter() {
            if keyboard.pressed(*key) {
                events.send(ControlEvent::TranslateEye(controller.translate_sensitivity * *dir));
            }
        }
    }
}

fn control_system(mut events: EventReader<ControlEvent>, mut cameras: Query<(&FpsCameraController, &mut LookTransform)>, time: Res<Time>) {
    if let Some((_, mut transform)) = cameras.iter_mut().find(|c| c.0.enabled) {
        let look_dir = transform.look_direction().unwrap();
        let mut angles = LookAngles::from_vector(look_dir);
        let dt = time.delta_seconds();
        for ev in events.read() {
            match ev {
                ControlEvent::Rotate(delta) => {
                    angles.add_yaw(dt * -delta.x);
                    angles.add_pitch(dt * -delta.y);
                }
                ControlEvent::TranslateEye(delta) => {
                    transform.eye += dt * delta.x * angles.unit_vector(); // simplified translation
                }
            }
        }
        transform.target = transform.eye + transform.radius() * angles.unit_vector();
    }
}

pub fn look_transform_system(mut cameras: Query<(&LookTransform, &mut Transform, Option<&mut Smoother>)>) {
    for (lt, mut tfm, smoother) in cameras.iter_mut() {
        if let Some(mut s) = smoother {
            if s.enabled {
                *tfm = s.smooth_transform(lt).into();
            }
        }
    }
}

#[derive(Debug, Clone, Copy, Default, Reflect)]
pub struct LookAngles { yaw: f32, pitch: f32 }

impl LookAngles {
    pub fn from_vector(v: Vec3) -> Self { let mut a = Self::default(); a.set_direction(v); a }
    pub fn set_direction(&mut self, v: Vec3) { let (y, p) = yaw_and_pitch_from_vector(v); self.yaw = y; self.pitch = p; }
    pub fn unit_vector(self) -> Vec3 { unit_vector_from_yaw_and_pitch(self.yaw, self.pitch) }
    pub fn add_yaw(&mut self, d: f32) { self.yaw = (self.yaw + d) % (2.0 * std::f32::consts::PI); }
    pub fn add_pitch(&mut self, d: f32) { self.pitch = (self.pitch + d).clamp(-std::f32::consts::FRAC_PI_2, std::f32::consts::FRAC_PI_2); }
    pub fn get_yaw(&self) -> f32 { self.yaw }
    pub fn get_pitch(&self) -> f32 { self.pitch }
}

fn yaw_and_pitch_from_vector(v: Vec3) -> (f32, f32) { (0.0, 0.0) }
fn unit_vector_from_yaw_and_pitch(yaw: f32, pitch: f32) -> Vec3 { Vec3::Z }

