pub struct OrbitCameraController {
    pub enabled: bool,
    pub mouse_rotate_sensitivity: Vec2,
    pub mouse_translate_sensitivity: Vec2,
    pub mouse_wheel_zoom_sensitivity: f32,
    pub pixels_per_line: f32,
    pub smoothing_weight: f32,
}

impl Default for OrbitCameraController {
    fn default() -> Self {
        Self { enabled: true, mouse_rotate_sensitivity: Vec2::splat(0.08), mouse_translate_sensitivity: Vec2::splat(0.1), mouse_wheel_zoom_sensitivity: 0.2, pixels_per_line: 53.0, smoothing_weight: 0.8 }
    }
}

#[derive(Event)]
pub enum ControlEvent { Orbit(Vec2), TranslateTarget(Vec2), Zoom(f32) }

fn on_controller_enabled_changed(mut query: Query<(&mut Smoother, &OrbitCameraController), Changed<OrbitCameraController>>) {
    for (mut smoother, controller) in query.iter_mut() { smoother.set_enabled(controller.enabled); }
}

fn default_input_map(mut events: EventWriter<ControlEvent>, mut mouse_wheel: EventReader<MouseWheel>, mut mouse_motion: EventReader<MouseMotion>, mouse_buttons: Res<ButtonInput<MouseButton>>, keyboard: Res<ButtonInput<KeyCode>>, controllers: Query<&OrbitCameraController>) {
    if let Some(controller) = controllers.iter().find(|c| c.enabled) {
        let mut delta = Vec2::ZERO;
        for ev in mouse_motion.read() { delta += ev.delta; }
        if keyboard.pressed(KeyCode::ControlLeft) { events.send(ControlEvent::Orbit(controller.mouse_rotate_sensitivity * delta)); }
        if mouse_buttons.pressed(MouseButton::Right) { events.send(ControlEvent::TranslateTarget(controller.mouse_translate_sensitivity * delta)); }
        let mut zoom = 1.0;
        for ev in mouse_wheel.read() {
            let amount = match ev.unit { MouseScrollUnit::Line => ev.y, MouseScrollUnit::Pixel => ev.y / controller.pixels_per_line };
            zoom *= 1.0 - amount * controller.mouse_wheel_zoom_sensitivity;
        }
        events.send(ControlEvent::Zoom(zoom));
    }
}

fn control_system(time: Res<Time>, mut events: EventReader<ControlEvent>, mut cameras: Query<(&OrbitCameraController, &mut LookTransform, &Transform)>) {
    if let Some((_, mut lt, scene_tf)) = cameras.iter_mut().find(|c| c.0.enabled) {
        let mut angles = LookAngles::from_vector(-lt.look_direction().unwrap());
        let dt = time.delta_seconds();
        for ev in events.read() {
            match ev {
                ControlEvent::Orbit(delta) => { angles.add_yaw(dt * -delta.x); angles.add_pitch(dt * delta.y); }
                ControlEvent::TranslateTarget(delta) => {
                    let right = scene_tf.rotation * -Vec3::X;
                    let up = scene_tf.rotation * Vec3::Y;
                    lt.target += dt * delta.x * right + dt * delta.y * up;
                }
                ControlEvent::Zoom(s) => { /* zoom handled by adjusting radius later */ }
            }
        }
        let radius = lt.radius();
        lt.eye = lt.target + radius * angles.unit_vector();
    }
}

pub fn look_transform_system(mut query: Query<(&LookTransform, &mut Transform, Option<&mut Smoother>)>) {
    for (lt, mut tfm, smoother) in query.iter_mut() {
        if let Some(mut s) = smoother { if s.enabled { *tfm = s.smooth_transform(lt).into(); } }
    }
}

