pub unsafe extern "C" fn sys_getenv(
    out_words: *mut u32,
    out_nwords: usize,
    varname: *const u8,
    varname_len: usize,
) -> usize {
    if cfg!(not(feature = "sys-getenv")) {
        let mut allowed = false;
        const ALLOWED_ENV_VARNAMES: &[&[u8]] = &[b"RUST_BACKTRACE", b"RUST_LIB_BACKTRACE", b"RISC0_KECCAK_PO2"];
        let var_slice = core::slice::from_raw_parts(varname, varname_len);
        for &allowed_name in ALLOWED_ENV_VARNAMES {
            if allowed_name == var_slice {
                allowed = true;
                break;
            }
        }
        if !allowed {
            const MSG: &[u8] = "sys_getenv not enabled for var".as_bytes();
            unsafe { sys_log(MSG.as_ptr(), MSG.len()) };
            const ERR: &[u8] = "sys_getenv is disabled; enable the sys-getenv feature flag".as_bytes();
            unsafe { sys_panic(ERR.as_ptr(), ERR.len()) };
        }
    }
    let Return(a0, _) = syscall_2(
        nr::SYS_GETENV,
        out_words,
        out_nwords,
        varname as u32,
        varname_len as u32,
    );
    if a0 == u32::MAX { usize::MAX } else { a0 as usize }
}

