    let mut out_buf = Vec::with_capacity(arr.value_data().len());
    let mut out_offsets = vec![0; arr.value_offsets().len()];
    let mut symbol_table = [0u8; FSST_SYMBOL_TABLE_SIZE];
    compress(
        &mut symbol_table,
        arr.value_data(),
        arr.value_offsets(),
        &mut out_buf,
        &mut out_offsets,
    )?;
    Ok((out_buf, out_offsets))
}

fn decompress_fsst(
    compressed: &[u8],
    offsets: &[i32],
) -> std::io::Result<Vec<u8>> {
    let mut out_buf = Vec::with_capacity(compressed.len() * 3);
    let mut out_offsets = vec![0; offsets.len()];
    let symbol_table = [0u8; FSST_SYMBOL_TABLE_SIZE];
    decompress(
        &symbol_table,
        compressed,
        offsets,
        &mut out_buf,
        &mut out_offsets,
    )?;
    Ok(out_buf)
}

