use std::ffi::{CString, CStr};
use pcap_sys as ffi;

type u_char = u8;

fn main() {
    let dev = CString::new("eth0").unwrap();
    let mut errbuf = [0i8; ffi::PCAP_ERRBUF_SIZE as usize];
    let handle = unsafe { ffi::pcap_create(dev.as_ptr(), errbuf.as_mut_ptr()) };
    if handle.is_null() {
        let err = unsafe { CStr::from_ptr(errbuf.as_ptr()) };
        panic!("Failed to create handle: {}", err.to_string_lossy());
    }
    unsafe { ffi::pcap_set_snaplen(handle, 65535) };
    unsafe { ffi::pcap_set_promisc(handle, 1) };
    unsafe { ffi::pcap_set_timeout(handle, 1000) };
    let res = unsafe { ffi::pcap_activate(handle) };
    if res != 0 {
        panic!("Failed to activate handle");
    }
    let filter_str = CString::new("tcp port 80").unwrap();
    let mut prog: ffi::bpf_program = unsafe { std::mem::zeroed() };
    unsafe {
        ffi::pcap_compile(handle, &mut prog, filter_str.as_ptr(), 1, 0);
        ffi::pcap_setfilter(handle, &mut prog);
        ffi::pcap_loop(handle, -1, Some(packet_cb), std::ptr::null_mut());
    }
}

