use std::borrow::Borrow;
use std::fmt;
use std::ops::RangeInclusive;

#[derive(Debug, Clone)]
pub struct Slice {
    pub start: Index,
    pub end: Index,
    pub step: Option<isize>,
}

impl fmt::Display for Slice {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "[{}:{}:{}]", self.start, self.end, self.step.map_or("".to_string(), |n| n.to_string()))
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Index {
    Head(usize),
    Tail(usize),
    Default,
}

use Index::*;

impl fmt::Display for Index {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Head(n) => write!(f, "{}", n),
            Tail(n) => write!(f, "-{}", n),
            Default => write!(f, ""),
        }
    }
}

impl Index {
    fn to_bound(&self, len: i128, r: &RangeInclusive<i128>) -> Option<i128> {
        match self {
            Head(n) => Some(*n as i128),
            Tail(n) => Some(len - (*n as i128)),
            Default => None,
        }
        .map(|n| clamp(n, r))
    }
}

fn clamp<T, R>(n: T, r: R) -> T
where
    T: Ord + Copy,
    R: Borrow<RangeInclusive<T>>, {
    let r = r.borrow();
    let (start, end) = (*r.start(), *r.end());
    n.max(start).min(end)
}

impl Slice {
    pub fn apply<'a, T>(&self, arr: &'a [T]) -> impl Iterator<Item = &'a T> + 'a {
        self.indices(arr.len()).map(move |i| &arr[i])
    }

    fn indices(&self, ulen: usize) -> impl Iterator<Item = usize> {
        let len = ulen as i128;
        let step = self.step.unwrap_or(1);
        let (def_start, def_end) = if step >= 0 { (0, len) } else { (len - 1, -1) };
        let bounds = if step >= 0 { def_start..=def_end } else { def_end..=def_start };
        Iter {
            i: self.start.to_bound(len, &bounds).unwrap_or(def_start),
            end: self.end.to_bound(len, &bounds).unwrap_or(def_end),
            step: step as i128,
        }
    }
}

struct Iter {
    i: i128,
    end: i128,
    step: i128,
}

impl Iterator for Iter {
    type Item = usize;
    fn next(&mut self) -> Option<usize> {
        if self.step == 0 {
            return None;
        }
        let i = self.i;
        self.i += self.step;
        let is_in_range = if self.step >= 0 { |a, b| a < b } else { |a, b| a > b };
        if is_in_range(i, self.end) {
            Some(i as usize)
        } else {
            None
        }
    }
}

