use std::fmt::{self, Display, Formatter};

pub struct ArgsError {
    desc: String,
}

impl ArgsError {
    pub fn new(scope: &str, msg: &str) -> ArgsError {
        ArgsError::new_with_usage(scope, msg, "")
    }
    pub fn new_with_usage(scope: &str, msg: &str, usage: &str) -> ArgsError {
        let mut desc = if scope.is_empty() { String::new() } else { format!("{}: ", scope) };
        desc.push_str(msg);
        if !usage.is_empty() { desc.push_str(&format!("\n\n{}", usage)); }
        ArgsError { desc }
    }
}
impl std::fmt::Debug for ArgsError {
    fn fmt(&self, f: &mut Formatter) -> fmt::Result { write!(f, "{}", self.desc) }
}
impl std::fmt::Display for ArgsError {
    fn fmt(&self, f: &mut Formatter) -> fmt::Result { write!(f, "{}", self.desc) }
}
impl std::error::Error for ArgsError {
    fn description(&self) -> &str { &self.desc }
}

pub enum Order {
    GreaterThan,
    GreaterThanOrEqual,
    LessThan,
    LessThanOrEqual,
}
impl Order {
    pub fn compare<T: PartialOrd>(&self, bound: &T, value: &T) -> bool {
        match *self {
            Order::GreaterThan => value > bound,
            Order::GreaterThanOrEqual => value >= bound,
            Order::LessThan => value < bound,
            Order::LessThanOrEqual => value <= bound,
        }
    }
}

pub struct OrderValidation<O: Clone + Display + PartialOrd> {
    bound: O,
    order: Order,
}
impl<O: Clone + Display + PartialOrd> OrderValidation<O> {
    pub fn new(order: Order, bound: O) -> OrderValidation<O> {
        OrderValidation { bound: bound.clone(), order }
    }
}
use args::validations::Validation;
impl<O: Clone + Display + PartialOrd> Validation for OrderValidation<O> {
    type T = O;
    fn error(&self, value: &O) -> ArgsError {
        ArgsError::new("order invalid", &format!("{} is not {} {}", value, self.order, self.bound))
    }
    fn is_valid(&self, value: &O) -> bool {
        self.order.compare(&self.bound, value)
    }
}

