pub const WORD_SIZE: usize = 4;

#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub struct ByteAddr(pub u32);

#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
