    pub fn new(triangles: Vec<Triangle>) -> Self {
        Mesh { triangles }
    }
    pub fn unique_vertices(&self) -> impl Iterator<Item = Vertex> + '_ {
        let mut set: HashSet<[u32; 3]> = HashSet::new();
        self.triangles.iter().flat_map(|t| t.vertices.iter()).filter_map(move |v| {
            let bits = [v[0].to_bits(), v[1].to_bits(), v[2].to_bits()];
            if set.insert(bits) {
                Some(*v)
            } else {
                None
            }
        })
    }
}

