pub fn escape_math(item: &str, result: &mut String) {
    for c in item.chars() {
        match c {
            '_' => result.push_str("\\_"),
            '*' => result.push_str("\\*"),
            '\\' => result.push_str("\\\\"),
            _ => result.push(c),
        }
    }
}

