use fax::{encoder::Encoder, slice_bits, Color, VecWriter, BitWriter};

let pbm_data = std::fs::read("image.pbm").unwrap();
let mut parts = pbm_data.splitn(3, |&b| b == b'\n');
let _header = parts.next().unwrap();
let size_line = std::str::from_utf8(parts.next().unwrap()).unwrap();
let (w_str, h_str) = size_line.split_once(' ').unwrap();
let width: u16 = w_str.parse().unwrap();
let height: u16 = h_str.parse().unwrap();
let image_bytes = parts.next().unwrap();
let mut writer = VecWriter::new();
let mut encoder = Encoder::new(writer);

for line in image_bytes.chunks((width as usize + 7) / 8).take(height as usize) {
    let pixels = slice_bits(line).take(width as usize).map(|b| if b { Color::Black } else { Color::White });
    encoder.encode_line(pixels, width).unwrap();
}
let fax_stream = encoder.finish().unwrap().finish();
std::fs::write("output.fax", fax_stream).unwrap();

