            None
        } else {
            Some(unsafe { Error::new_unchecked(errno) })
        }
    }

    pub const unsafe fn new_unchecked(errno: u16) -> Error {
        Error(num::NonZeroU16::new_unchecked(errno))
    }
}

impl fmt::LowerHex for Error {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        self.0.fmt(f)
    }
}

