impl H256 {
    pub fn as_bytes(&self) -> &[u8] {
        &self.0[..]
    }
    pub fn from_slice(input: &[u8]) -> Result<Self, crate::error::FromSliceError> {
        if input.len() != 32 {
            Err(crate::error::FromSliceError::InvalidLength(input.len()))
        } else {
            let mut ret = Self::default();
            ret.0[..].copy_from_slice(input);
            Ok(ret)
        }
    }
}

