use amy::{Poller, Registrar, Event};
use std::time::Duration;

fn main() -> std::io::Result<()> {
    let mut poller = Poller::new()?;
    let registrar = poller.get_registrar();

    // Set a recurring timer that fires every 200 ms
    let timer_id = registrar.set_interval(200)?;

    // Handle three timer events
    for _ in 0..3 {
        let notifications = poller.wait(500)?;
        let timer_notification = notifications.into_iter()
            .find(|n| n.id == timer_id)
            .expect("timer not fired");
        assert_eq!(timer_notification.event, Event::Read);
        println!("Timer fired");
    }

    // Cancel the timer
    registrar.cancel_timeout(timer_id)?;

    Ok(())
}

