    Exact(u8),
    AtLeast(u8),
}

pub const SINK_STATE: u32 = 0;

pub struct DFA {
    transitions: Vec<[u32; 256]>,
    distances: Vec<Distance>,
    initial_state: u32,
}

impl DFA {
    pub fn initial_state(&self) -> u32 { self.initial_state }
    pub fn transition(&self, state: u32, b: u8) -> u32 { self.transitions[state as usize][b as usize] }
    pub fn distance(&self, state: u32) -> Distance { self.distances[state as usize] }
    pub fn eval<B: AsRef<[u8]>>(&self, text: B) -> Distance {
        let mut state = self.initial_state();
        for &b in text.as_ref() {
            state = self.transition(state, b);
        }
        self.distance(state)
    }
}

