use std::borrow::Cow;
use std::time::{Duration, Instant};

pub struct LinearModel {
    done: usize,
    total: usize,
    message: Cow<'static, str>,
    start: Instant,
}

impl LinearModel {
    pub fn new<S: Into<Cow<'static, str>>>(message: S, total: usize) -> LinearModel {
        LinearModel {
            done: 0,
            total,
            message: message.into(),
            start: Instant::now(),
        }
    }

    pub fn set_done(&mut self, done: usize) {
        self.done = done;
    }

    pub fn increment(&mut self, i: usize) {
        self.done += i;
    }
}

pub fn percent_done(done: usize, total: usize) -> String {
    if total == 0 || done > total {
        "??%".into()
    } else {
        format!("{:.1}%", done as f64 * 100.0 / total as f64)
    }
}

pub fn estimate_remaining(start: &Instant, done: usize, total: usize) -> String {
    let elapsed = start.elapsed();
    if total == 0 || done == 0 || elapsed.is_zero() || done > total {
        "??".into()
    } else {
        let remaining = elapsed.as_secs_f64() / done as f64 * (total as f64 - done as f64);
        format!("{:.0}s", remaining)
    }
}

pub trait Model {
    fn render(&mut self, width: usize) -> String;
}

impl Model for LinearModel {
    fn render(&mut self, _width: usize) -> String {
        format!(
            "{}: {}/{}, {}, {} remaining",
            self.message,
            self.done,
            self.total,
            percent_done(self.done, self.total),
            estimate_remaining(&self.start, self.done, self.total)
        )
    }
}

