use std::thread;
use std::time::Duration;

struct Indicator {
    position: usize,
    width: usize,
}

impl Indicator {
    fn new(width: usize) -> Self {
        Self { position: 0, width }
    }
}

impl nutmeg::Model for Indicator {
    fn render(&mut self, _width: usize) -> String {
        let mut line = vec![b' '; self.width];
        if self.position < self.width {
            line[self.position] = b'*';
        } else {
            line[self.width - 1] = b'*';
        }
        String::from_utf8(line).unwrap()
    }
}

fn main() {
    let options = nutmeg::Options::default().update_interval(Duration::from_millis(25));
    let indicator = Indicator::new(20);
    let view = nutmeg::View::new(indicator, options);

    for i in 0..1000 {
        view.update(|m| {
            m.position = ((i as f64) * 3.0).min((m.width - 1) as f64) as usize;
        });
        thread::sleep(Duration::from_millis(100));
    }
}

