use fedimint_core::secp256k1::PublicKey;
use bitcoin::hashes::sha256::Hash as Sha256;

#[derive(Debug, Clone, Eq, PartialEq, Hash, serde::Serialize, serde::Deserialize, fedimint_core::encoding::Encodable, fedimint_core::encoding::Decodable)]
pub struct PrunedInvoice {
    pub amount: Amount,
    pub destination: PublicKey,
    #[serde(with = "fedimint_core::hex::serde", default)]
    pub destination_features: Vec<u8>,
    pub payment_hash: Sha256,
    pub payment_secret: [u8; 32],
    pub route_hints: Vec<fedimint_ln_common::route_hints::RouteHint>,
    pub min_final_cltv_delta: u64,
    pub expiry_timestamp: u64,
}

impl PrunedInvoice {
    pub fn new(invoice: &Bolt11Invoice, amount: Amount) -> Self {
        let expiry_timestamp = invoice.expires_at().map_or(u64::MAX, |t| t.as_secs());
        PrunedInvoice {
            amount,
            destination: invoice
                .payee_pub_key()
                .copied()
                .unwrap_or_else(|| invoice.recover_payee_pub_key()),
            destination_features: Vec::new(),
            payment_hash: *invoice.payment_hash(),
            payment_secret: invoice.payment_secret().0,
            route_hints: Vec::new(),
            min_final_cltv_delta: invoice.min_final_cltv_expiry_delta(),
            expiry_timestamp,
        }
    }
}

