use std::vec::Vec;

const CSI: &str = "\x1b[";

#[derive(Debug, PartialEq, Eq)]
pub struct Match<'t> {
    pub start: usize,
    pub end: usize,
    pub text: &'t str,
}

fn terminated_byte(byte: u8) -> bool {
    (0x40..=0x7e).contains(&byte)
}

pub fn parse(text: &str) -> Vec<Match> {
    let mut v = Vec::with_capacity(8);
    let csi_len = CSI.len();
    let mut s = text;
    let mut start = 0;
    let mut end = start + csi_len;
    while end <= text.len() {
        if s.starts_with(CSI) {
            while end < text.len() && !terminated_byte(text.as_bytes()[end]) {
                end += 1;
            }
            let end = end + 1;
            if end > text.len() {
                break;
            }
            v.push(Match {
                start,
                end,
                text: &text[start..end],
            });
            start = end;
        } else {
            start += s.chars().next().expect("non-empty-str").len_utf8();
        }
        s = &text[start..];
        end = start + csi_len;
    }
    v
}

