#[derive(Clone, Debug)]
pub enum Resolver {
    Function(fn(u64) -> usize),
    Expr(crate::plurals::Ast),
}

impl Resolver {
    pub fn resolve(&self, n: u64) -> usize {
        match *self {
            Resolver::Function(f) => f(n),
            Resolver::Expr(ref ast) => ast.resolve(n),
        }
    }
}

pub struct ParseOptions {
    force_plural: Option<fn(u64) -> usize>,
    force_encoding: Option<encoding::label::EncodingRef>,
}

impl ParseOptions {
    pub fn new() -> Self {
        ParseOptions { force_plural: None, force_encoding: None }
    }
    pub fn force_plural(mut self, f: fn(u64) -> usize) -> Self {
        self.force_plural = Some(f);
        self
    }
    pub fn parse<R: std::io::Read>(self, _reader: R) -> Result<Catalog, Error> {
        let resolver = match self.force_plural {
            Some(f) => Resolver::Function(f),
            None => Resolver::Function(crate::plurals::default_resolver),
        };
        Ok(Catalog { strings: HashMap::new(), resolver })
    }
}

