pub struct FruitApp {
    // fields omitted for brevity
}

impl FruitApp {
    pub fn bundled_resource_path(name: &str, extension: &str) -> Option<String> {
        unsafe {
            let cls = objc::runtime::Class::get("NSBundle").unwrap();
            let bundle: *mut objc::runtime::Object = msg_send![cls, mainBundle];
            let cls = objc::runtime::Class::get("NSString").unwrap();
            let objc_str: *mut objc::runtime::Object = msg_send![cls, alloc];
            let objc_name: *mut objc::runtime::Object = msg_send![objc_str,
                initWithBytes:name.as_ptr()
                length:name.len()
                encoding:4];
            let objc_ext: *mut objc::runtime::Object = msg_send![objc_str,
                initWithBytes:extension.as_ptr()
                length:extension.len()
                encoding:4];
            let ini: *mut objc::runtime::Object = msg_send![bundle,
                pathForResource:objc_name
                ofType:objc_ext];
            let _:() = msg_send![objc_name, release];
            let _:() = msg_send![objc_ext, release];
            let cstr: *const i8 = msg_send![ini, UTF8String];
            if cstr != std::ptr::null() {
                let rstr = std::ffi::CStr::from_ptr(cstr).to_string_lossy().into_owned();
                return Some(rstr);
            }
            None
        }
    }
}

