macro_rules! alloc_stack {
    ([$item_type:ty; $len:expr]) => {{
        let space: [$item_type; $len] = [Default::default(); $len];
        space
    }};
}

pub enum ErrorKind { NoSpace }

pub type Result<T> = core::result::Result<T, ErrorKind>;

pub struct FixedVec<'a, T: 'a + Copy> { memory: &'a mut [T], len: usize }

impl<'a, T> FixedVec<'a, T>
where T: 'a + Copy {
    pub fn new(memory: &'a mut [T]) -> Self { FixedVec { memory, len: 0 } }
    pub fn capacity(&self) -> usize { self.memory.len() }
    pub fn as_slice(&self) -> &[T] { &self.memory[..self.len] }
    pub fn resize(&mut self, new_len: usize, value: T) {
        assert!(new_len <= self.capacity());
        if new_len <= self.len {
            self.len = new_len;
        } else {
            for i in self.memory[self.len..new_len].iter_mut() { *i = value; }
            self.len = new_len;
        }
    }
}

