use ffi_helpers::task::{Task, CancellationToken};
use std::thread;
use std::time::Duration;

#[derive(Clone, Copy)]
struct Spin;

impl Task for Spin {
    type Output = usize;
    fn run(&self, cancel: &CancellationToken) -> Result<Self::Output, anyhow::Error> {
        let mut count = 0;
        while !cancel.cancelled() {
            thread::sleep(Duration::from_millis(10));
            count += 1;
        }
        Ok(count)
    }
}

