use coremidi_sys as cm;
use std::mem;

fn main() {
    const BUFFER_SIZE: usize = 1024;
    let mut buffer = [0u8; BUFFER_SIZE];
    let evtlist_ptr = buffer.as_mut_ptr() as *mut cm::MIDIEventList;

    unsafe {
        let mut pkt = cm::MIDIEventListInit(evtlist_ptr, cm::kMIDIProtocol_2_0 as cm::MIDIProtocolID);
        pkt = cm::MIDIEventListAdd(
            evtlist_ptr,
            BUFFER_SIZE as cm::ByteCount,
            pkt,
            0,
            2,
            [0x90u32, 0x40u32].as_ptr(),
        );
        // Iterate over packets
        let mut current = &(*evtlist_ptr).packet as *const cm::MIDIEventPacket;
        loop {
            let count = unsafe { (*current).wordCount as usize };
            let words = unsafe { &(*current).words[0..count] };
            println!("Packet words: {:?}", words);
            let next = cm::MIDIEventPacketNext(current);
            if next == current { break; }
            current = next;
        }
    }
}

