use core::fmt::{self, Display, Formatter};
use std::ffi::OsStr;
use std::path::Path;

pub trait Quotable {
    fn quote(&self) -> Quoted<'_>;
}

impl Quotable for str {
    fn quote(&self) -> Quoted<'_> {
        Quoted::native(self)
    }
}

impl Quotable for Path {
    fn quote(&self) -> Quoted<'_> {
        Quoted::native(self.as_os_str())
    }
}

pub struct Quoted<'a> {
    source: Kind<'a>,
    force_quote: bool,
    #[cfg(any(feature = "windows", all(feature = "native", windows)))]
    external: bool,
}

#[derive(Debug, Copy, Clone)]
enum Kind<'a> {
    #[cfg(any(feature = "unix", all(feature = "native", not(windows))))]
    Unix(&'a str),
    #[cfg(feature = "unix")]
    UnixRaw(&'a [u8]),
    #[cfg(any(feature = "windows", all(feature = "native", windows)))]
    Windows(&'a str),
    #[cfg(feature = "windows")]
    #[cfg(feature = "alloc")]
    WindowsRaw(&'a [u16]),
    #[cfg(feature = "native")]
    #[cfg(feature = "std")]
    NativeRaw(&'a OsStr),
}

impl<'a> Quoted<'a> {
    #[cfg(feature = "native")]
    pub fn native(text: &'a str) -> Self {
        #[cfg(windows)]
        return Quoted { source: Kind::Windows(text), force_quote: true, external: false };
        #[cfg(not(windows))]
        return Quoted { source: Kind::Unix(text), force_quote: true, external: false };
    }

    #[cfg(feature = "native")]
    pub fn native_raw(text: &'a OsStr) -> Self {
        Quoted { source: Kind::NativeRaw(text), force_quote: true, external: false }
    }

    pub fn to_string(&self) -> String {
        format!("{}", self)
    }
}

impl<'a> Display for Quoted<'a> {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        // Simplified placeholder implementation for demonstration purposes.
        write!(f, "quoted")
    }
}

