pub struct LineSpan<'a> {
    text: &'a str,
    start: usize,
    end: usize,
    ending: usize,
}

impl<'a> LineSpan<'a> {
    pub fn start(&self) -> usize { self.start }
    pub fn end(&self) -> usize { self.end }
    pub fn as_str(&self) -> &'a str { &self.text[self.start..self.end] }
}

pub struct LineSpanIter<'a> {
    text: &'a str,
    iter: core::str::Lines<'a>,
}

impl<'a> LineSpanIter<'a> {
    fn from(text: &'a str) -> Self {
        Self { text, iter: text.lines() }
    }
}

impl<'a> Iterator for LineSpanIter<'a> {
    type Item = LineSpan<'a>;
    fn next(&mut self) -> Option<Self::Item> {
        if let Some(line) = self.iter.next() {
            let core::ops::Range { start, end } = str_to_range_unchecked(self.text, line);
            let ending = find_next_line_start(self.text, end).unwrap_or(self.text.len());
            Some(LineSpan { text: self.text, start, end, ending })
        } else {
            None
        }
    }
}

pub trait LineSpans {
    fn line_spans(&self) -> LineSpanIter<'_>;
}

impl LineSpans for str {
    fn line_spans(&self) -> LineSpanIter<'_> {
        LineSpanIter::from(self)
    }
}

fn find_next_line_start(text: &str, index: usize) -> Option<usize> {
    let i = text[index..].find('\n')?;
    Some(index + i + 1)
}

fn str_to_range_unchecked<'a>(string: &'a str, substring: &'a str) -> core::ops::Range<usize> {
    let start = (substring.as_ptr() as usize) - (string.as_ptr() as usize);
    let end = start + substring.len();
    core::ops::Range { start, end }
}

