use candid::Principal;
pub const CANISTER_SIG_PK_DER_OID: &[u8; 14] = b"\x30\x0C\x06\x0A\x2B\x06\x01\x04\x01\x83\xB8\x43\x01\x02";
pub const CANISTER_SIG_PK_DER_PREFIX_LENGTH: usize = 19;
#[derive(Clone, Eq, PartialEq, Debug)]
pub struct CanisterSigPublicKey {
    pub canister_id: Principal,
    pub seed: Vec<u8>,
}
impl CanisterSigPublicKey {
    pub fn new(canister_id: Principal, seed: Vec<u8>) -> Self {
        Self { canister_id, seed }
    }
    pub fn to_raw(&self) -> Vec<u8> {
        let mut raw = Vec::new();
        raw.push(self.canister_id.as_ref().len() as u8);
        raw.extend(self.canister_id.as_ref());
        raw.extend(&self.seed);
        raw
    }
    pub fn to_der(&self) -> Vec<u8> {
        let raw = self.to_raw();
        let mut der = Vec::new();
        der.push(0x30);
        der.push(17 + raw.len() as u8);
        der.extend(CANISTER_SIG_PK_DER_OID);
        der.push(0x03);
        der.push(1 + raw.len() as u8);
        der.push(0x00);
        der.extend(raw);
        der
    }
}

