#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub struct SourceType {
    pub language: Language,
    pub module_kind: ModuleKind,
    pub variant: LanguageVariant,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum Language {
    JavaScript = 0,
    TypeScript = 1,
    TypeScriptDefinition = 2,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum ModuleKind {
    Script = 0,
    Module = 1,
    Unambiguous = 2,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum LanguageVariant {
    Standard = 0,
    Jsx = 1,
}

impl SourceType {
    pub const fn cjs() -> Self {
        Self { language: Language::JavaScript, module_kind: ModuleKind::Script, variant: LanguageVariant::Standard }
    }
    pub const fn mjs() -> Self {
        Self { language: Language::JavaScript, module_kind: ModuleKind::Module, variant: LanguageVariant::Standard }
    }
    pub const fn jsx() -> Self {
        Self::mjs().with_jsx(true)
    }
    pub const fn ts() -> Self {
        Self { language: Language::TypeScript, module_kind: ModuleKind::Module, variant: LanguageVariant::Standard }
    }
    pub const fn tsx() -> Self {
        Self::ts().with_jsx(true)
    }
    pub const fn d_ts() -> Self {
        Self { language: Language::TypeScriptDefinition, module_kind: ModuleKind::Module, variant: LanguageVariant::Standard }
    }
    pub const fn with_jsx(mut self, yes: bool) -> Self {
        if yes { self.variant = LanguageVariant::Jsx; }
        self
    }
    pub fn is_module(self) -> bool { self.module_kind == ModuleKind::Module }
    pub fn from_path<P: AsRef<Path>>(path: P) -> Result<Self, UnknownExtension> {
        let ext = path.as_ref().extension().and_then(|s| s.to_str()).ok_or_else(|| UnknownExtension::new("Missing extension"))?;
        match ext {
            "js" | "mjs" | "cjs" | "jsx" => Ok(Self::mjs()),
            "ts" | "tsx" | "mts" | "cts" => Ok(Self::ts()),
            "d.ts" => Ok(Self::d_ts()),
            _ => Err(UnknownExtension::new("Unsupported extension")),
        }
    }
}

