use aotuv_lancer_vorbis_sys::*;
use std::fs::File;
use std::io::{Cursor, Read};
use std::mem::MaybeUninit;
use std::os::raw::c_void;
use std::ptr;
use std::slice;
use std::ffi::CStr;

fn main() {
    // Load file into memory (simplified example)
    let mut data = Vec::new();
    File::open("audio.ogg").unwrap().read_to_end(&mut data).unwrap();
    let mut cursor = Cursor::new(&data[..]);

    // Simple read callback
    unsafe extern "C" fn read_func(
        ptr: *mut c_void,
        size: usize,
        nmemb: usize,
        datasource: *mut c_void,
    ) -> usize {
        let src = &mut *(datasource as *mut Cursor<&[u8]>);
        let buf = slice::from_raw_parts_mut(ptr as *mut u8, size * nmemb);
        match src.read(buf) {
            Ok(n) => n / size,
            Err(_) => 0,
        }
    }

    let callbacks = ov_callbacks {
        read_func: Some(read_func),
        seek_func: None,
        close_func: None,
        tell_func: None,
    };

    let mut vf = MaybeUninit::uninit();
    unsafe {
        let ret = ov_open_callbacks(
            &mut cursor as *mut _ as *mut c_void,
            vf.as_mut_ptr(),
            ptr::null(),
            0,
            callbacks,
        );
        assert_eq!(ret, 0, "Failed to open Ogg Vorbis file");
        let vf = vf.assume_init_mut();

        // Retrieve the comment structure
        let comment_ptr = ov_comment(vf, -1);
        if comment_ptr.is_null() {
            println!("No comments present");
        } else {
            let comment = &*comment_ptr;
            // user_comments is a NULL‑terminated array of C strings
            let mut i = 0;
            while !(*comment.user_comments.add(i)).is_null() {
                let c_str = CStr::from_ptr(*comment.user_comments.add(i));
                println!("Comment: {}", c_str.to_string_lossy());
                i += 1;
            }
        }

        // Clean up
        ov_clear(vf);
    }
}

