use core::convert::TryFrom;

#[derive(Debug, Clone, PartialEq, Eq, Hash, Ord, PartialOrd)]
pub enum KeyCode {
    Char(char),
    Physical(PhysKeyCode),
    Shift,
    Control,
    Alt,
    Super,
    Meta,
    Hyper,
    CapsLock,
    Function(u8),
    // other variants omitted for brevity
}

