pub enum PhysKeyCode {
    A,
    B,
    // other variants omitted for brevity
}

impl TryFrom<&str> for KeyCode {
    type Error = String;
    fn try_from(s: &str) -> Result<Self, String> {
        match s {
            "Shift" => Ok(KeyCode::Shift),
            "Control" => Ok(KeyCode::Control),
            "Alt" => Ok(KeyCode::Alt),
            "Super" => Ok(KeyCode::Super),
            "Meta" => Ok(KeyCode::Meta),
            "Hyper" => Ok(KeyCode::Hyper),
            "CapsLock" => Ok(KeyCode::CapsLock),
            "Enter" => Ok(KeyCode::Char('\r')),
            "Tab" => Ok(KeyCode::Char('\t')),
            "Backspace" => Ok(KeyCode::Char('\u{8}')),
            "Escape" => Ok(KeyCode::Char('\u{1b}')),
            s if s.starts_with('F') => {
                let num = &s[1..];
                match num.parse::<u8>() {
                    Ok(n) if n >= 1 && n <= 24 => Ok(KeyCode::Function(n)),
                    _ => Err(format!("invalid function key {}", s)),
                }
            }
            _ => Err(format!("invalid KeyCode string {}", s)),
        }
    }
}

