use nom::bytes::complete::{tag, take_until};
use nom::IResult;
use nom_locate::{position, LocatedSpan};

type Span<'a> = LocatedSpan<&'a str>;

fn parse_foobar(s: Span) -> IResult<Span, Span> {
    let (s, _) = take_until("foo")(s)?;
    let (s, pos) = position(s)?;
    let (s, _) = tag("foo")(s)?;
    Ok((s, pos))
}

