pub struct Elf<'a> {
    data: &'a [u8],
}

impl<'a> Elf<'a> {
    pub fn new(data: &'a [u8]) -> Self { Elf { data } }

    pub fn append<W: Write>(&self, name: &str, sectdata: &[u8], writer: &mut W) -> Result<(), Error> {
        let mut elf = self.data.to_vec();
        elf.extend_from_slice(sectdata);
        const MAGIC: u32 = 0x501e;
        let trailer_len: u64 = 8 + 4 + 4;
        elf.extend_from_slice(&MAGIC.to_le_bytes());
        let hash = {
            let mut h: u32 = 0;
            for b in name.bytes() { h = h.wrapping_add(b as u32); }
            h
        };
        elf.extend_from_slice(&hash.to_le_bytes());
        let total_len = (sectdata.len() as u64) + trailer_len;
        elf.extend_from_slice(&total_len.to_le_bytes());
        writer.write_all(&elf)?;
        Ok(())
    }
}

