type dispatch_semaphore_t = *mut c_void;

extern {
    fn dispatch_semaphore_create(value: c_long) -> dispatch_semaphore_t;
    fn dispatch_semaphore_wait(dsema: dispatch_semaphore_t, timeout: u64) -> c_long;
    fn dispatch_semaphore_signal(dsema: dispatch_semaphore_t) -> c_long;
}

pub const DISPATCH_TIME_FOREVER: u64 = !0;

pub struct Semaphore {
    ptr: dispatch_semaphore_t,
}

impl Semaphore {
    pub fn new(value: u32) -> Self {
        let ptr = unsafe { dispatch_semaphore_create(value as c_long) };
        Semaphore { ptr }
    }
    fn wait(&self) {
        let _ = unsafe { dispatch_semaphore_wait(self.ptr, DISPATCH_TIME_FOREVER) };
    }
    pub fn access(&self) -> SemaphoreGuard {
        self.wait();
        SemaphoreGuard::new(self.clone())
    }
}

impl Clone for Semaphore {
    fn clone(&self) -> Self {
        Semaphore { ptr: self.ptr }
    }
}

pub struct SemaphoreGuard {
    sem: Semaphore,
}

impl SemaphoreGuard {
    fn new(sem: Semaphore) -> SemaphoreGuard {
        SemaphoreGuard { sem }
    }
    pub fn signal(self) {}
}

impl Drop for SemaphoreGuard {
    fn drop(&mut self) {
        unsafe { dispatch_semaphore_signal(self.sem.ptr); }
    }
}

