        Quoted { source: Kind::Unix(text), force_quote: true, external: false }
    }
    pub fn unix_raw(bytes: &'a [u8]) -> Self {
        Quoted { source: Kind::UnixRaw(bytes), force_quote: true, external: false }
    }
    pub fn windows(text: &'a str) -> Self {
        Quoted { source: Kind::Windows(text), force_quote: true, external: false }
    }
    pub fn force(mut self, force: bool) -> Self {
        self.force_quote = force;
        self
    }
    pub fn external(mut self, external: bool) -> Self {
        self.external = external;
        self
    }
}

pub trait Quotable {
    fn quote(&self) -> Quoted<'_>;
    fn maybe_quote(&self) -> Quoted<'_> {
        let mut q = self.quote();
        q.force_quote = false;
        q
    }
}

impl Quotable for str {
    fn quote(&self) -> Quoted<'_> {
        Quoted::unix(self)
    }
}

