pub fn escape_cirru_leaf(s: &str) -> String {
    let mut chunk = String::with_capacity(s.len() + 2);
    chunk.push('"');
    for c in s.chars() {
        match c {
            '\n' => chunk.push_str("\\n"),
            '\t' => chunk.push_str("\\t"),
            '"' => chunk.push_str("\\\""),
            '\\' => chunk.push_str("\\\\"),
            '\'' => chunk.push_str("\\'"),
            _ => chunk.push(c),
        }
    }
    chunk.push('"');
    chunk
}

