unsafe extern "C" fn read_func(
    ptr: *mut std::ffi::c_void,
    size: usize,
    nmemb: usize,
    datasource: *mut std::ffi::c_void,
) -> usize {
    let file = &mut *(datasource as *mut std::fs::File);
    let buf = std::slice::from_raw_parts_mut(ptr as *mut u8, size * nmemb);
    match file.read(buf) {
        Ok(n) => n / size,
        Err(_) => 0,
    }
}

