use blake3;
use bytemuck;
use bs58;
use std::fmt;
use std::str;

pub struct LtHash(pub [u16; LtHash::NUM_ELEMENTS]);

impl LtHash {
    pub const NUM_ELEMENTS: usize = 1024;
    pub const fn identity() -> Self { Self([0; Self::NUM_ELEMENTS]) }
    pub fn with(hasher: &blake3::Hasher) -> Self {
        let mut reader = hasher.finalize_xof();
        let mut new = Self::identity();
        reader.fill(bytemuck::must_cast_slice_mut(new.0.as_mut_slice()));
        new
    }
    pub fn checksum(&self) -> Checksum {
        let hash = blake3::hash(bytemuck::must_cast_slice(&self.0));
        Checksum(hash.into())
    }
}

pub struct Checksum(pub [u8; Checksum::NUM_ELEMENTS]);

impl Checksum {
    pub const NUM_ELEMENTS: usize = 32;
}

impl fmt::Display for Checksum {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        const MAX_BASE58_LEN: usize = 44;
        let mut buf = [0u8; MAX_BASE58_LEN];
        let len = bs58::encode(&self.0).onto(buf.as_mut_slice()).unwrap();
        let s = str::from_utf8(&buf[..len]).unwrap();
        write!(f, "{}", s)
    }
}

