use short_uuid::converter::BaseConverter;
use short_uuid::error::InvalidShortUuid;

type Bytes = Vec<u8>;

pub struct ShortUuid(Bytes);

impl ShortUuid {
    pub fn parse_str(s: &str) -> Result<Self, InvalidShortUuid> {
        if s.len() != 22 {
            return Err(InvalidShortUuid);
        }
        Ok(ShortUuid(s.as_bytes().to_vec()))
    }
    pub fn to_uuid(self) -> uuid::Uuid {
        let converter = BaseConverter::default();
        let hex = converter.convert_to_hex(&self.0).unwrap();
        format_uuid(hex)
    }
}

fn format_uuid(value: String) -> uuid::Uuid {
    let formatted = format!(
        "{}-{}-{}-{}-{}",
        &value[0..8],
        &value[8..12],
        &value[12..16],
        &value[16..20],
        &value[20..32]
    );
    uuid::Uuid::parse_str(&formatted).unwrap()
}

