use std::path::PathBuf;
use semver::Version;
use risc0_zkvm_platform::memory;
use risc0_binfmt::KERNEL_START_ADDR;
use serde::{Deserialize, Serialize};

#[derive(Serialize, Deserialize, Clone, Default)]
pub struct GuestMetadata {
    pub rustc_flags: Option<Vec<String>>,
    pub kernel: bool,
}

fn get_rust_toolchain_version() -> Version {
    let rzup = rzup::Rzup::new().unwrap();
    let Some((version, _)) = rzup.get_default_version(&rzup::Component::RustToolchain).unwrap() else {
        panic!("Risc Zero Rust toolchain not found. Try running `rzup install rust`");
    };
    version
}

fn encode_rust_flags(guest_meta: &GuestMetadata, escape_special_chars: bool) -> String {
    let lower_atomic = if get_rust_toolchain_version() > Version::new(1, 81, 0) {
        "passes=lower-atomic"
    } else {
        "passes=loweratomic"
    };
    let rustc_flags = guest_meta.rustc_flags.clone().unwrap_or_default();
    let rustc_flags: Vec<_> = rustc_flags.iter().map(|s| s.as_str()).collect();
    let text_addr = if guest_meta.kernel {
        KERNEL_START_ADDR.0
    } else {
        memory::TEXT_START
    };
    [
        rustc_flags.as_slice(),
        &[
            "-C",
            lower_atomic,
            "-C",
            &format!("link-arg=-Ttext={:#010x}", text_addr),
            "-C",
            "link-arg=--fatal-warnings",
            "-C",
            "panic=abort",
            "--cfg",
            "getrandom_backend=\"custom\"",
        ],
    ]
    .concat()
    .iter()
    .map(|x| {
        if escape_special_chars {
            x.escape_default().to_string()
        } else {
            x.to_string()
        }
    })
