pub struct Pipe {
    pub read: FileDescriptor,
    pub write: FileDescriptor,
}

impl Pipe {
    #[cfg(target_os = "linux")]
    pub fn new() -> Result<Pipe, Error> {
        let mut fds = [-1i32; 2];
        let res = unsafe { libc::pipe2(fds.as_mut_ptr(), libc::O_CLOEXEC) };
        if res == -1 {
            Err(Error::Pipe(std::io::Error::last_os_error()))
        } else {
            let read = FileDescriptor { handle: OwnedHandle { handle: fds[0], handle_type: () } };
            let write = FileDescriptor { handle: OwnedHandle { handle: fds[1], handle_type: () } };
            Ok(Pipe { read, write })
        }
    }
    #[cfg(not(target_os = "linux"))]
    pub fn new() -> Result<Pipe, Error> {
        let mut fds = [-1i32; 2];
        let res = unsafe { libc::pipe(fds.as_mut_ptr()) };
        if res == -1 {
            Err(Error::Pipe(std::io::Error::last_os_error()))
        } else {
            let read = FileDescriptor { handle: OwnedHandle { handle: fds[0], handle_type: () } };
            let write = FileDescriptor { handle: OwnedHandle { handle: fds[1], handle_type: () } };
            read.handle.cloexec()?;
            write.handle.cloexec()?;
            Ok(Pipe { read, write })
        }
    }
}

