#[repr(transparent)]
pub struct HSTRING(pub(crate) *mut HStringHeader);
impl HSTRING { pub const fn new() -> Self { Self(core::ptr::null_mut()) } }

pub struct HStringBuilder(*mut HStringHeader);
impl HStringBuilder {
    pub fn new(len: usize) -> Self {
        let header = HStringHeader::alloc(len as u32);
        Self(header)
    }
    pub fn as_bytes_mut(&mut self) -> &mut [u8] {
        if let Some(header) = unsafe { self.0.as_ref() } {
            unsafe { core::slice::from_raw_parts_mut(header.data as *mut u8, header.len as usize * 2) }
        } else {
            &mut []
        }
    }
}

impl From<HStringBuilder> for HSTRING {
    fn from(value: HStringBuilder) -> Self {
        if let Some(header) = unsafe { value.0.as_ref() } {
            unsafe { (*header).data.offset((*header).len as isize).write(0) };
            let result = HSTRING(value.0);
            core::mem::forget(value);
            result
        } else {
            HSTRING::new()
        }
    }
}

