pub fn socketpair() -> Result<(FileDescriptor, FileDescriptor), Error> {
    socketpair_impl()
}

#[cfg(target_os = "linux")]
fn socketpair_impl() -> Result<(FileDescriptor, FileDescriptor), Error> {
    let mut fds = [-1i32; 2];
    let res = unsafe { libc::socketpair(libc::PF_LOCAL, libc::SOCK_STREAM | libc::SOCK_CLOEXEC, 0, fds.as_mut_ptr()) };
    if res == -1 {
        Err(Error::Socketpair(std::io::Error::last_os_error()))
    } else {
        let a = FileDescriptor { handle: OwnedHandle { handle: fds[0], handle_type: () } };
        let b = FileDescriptor { handle: OwnedHandle { handle: fds[1], handle_type: () } };
        Ok((a, b))
    }
}

#[cfg(not(target_os = "linux"))]
fn socketpair_impl() -> Result<(FileDescriptor, FileDescriptor), Error> {
    let mut fds = [-1i32; 2];
    let res = unsafe { libc::socketpair(libc::AF_UNIX, libc::SOCK_STREAM, 0, fds.as_mut_ptr()) };
    if res == -1 {
        Err(Error::Socketpair(std::io::Error::last_os_error()))
    } else {
        let a = FileDescriptor { handle: OwnedHandle { handle: fds[0], handle_type: () } };
        let b = FileDescriptor { handle: OwnedHandle { handle: fds[1], handle_type: () } };
        a.handle.cloexec()?;
        b.handle.cloexec()?;
        Ok((a, b))
    }
}

