use versatiles_container::{get_reader, convert_tiles_container, TilesConverterParameters};
use versatiles_core::types::{TileBBoxPyramid, GeoBBox, TileCompression};
use anyhow::Result;

#[tokio::main]
async fn main() -> Result<()> {
    let input = "../testdata/berlin.mbtiles";
    let output = "../testdata/berlin_subset.versatiles";

    // Open the source container
    let mut reader = get_reader(input).await?;

    // Define a geographic bounding box (lon_min, lat_min, lon_max, lat_max)
    let bbox = GeoBBox::try_from(vec![13.0, 52.0, 13.5, 52.5])?;

    // Create a TileBBoxPyramid covering the whole zoom range
    let mut pyramid = TileBBoxPyramid::new_full(32);
    pyramid.intersect_geo_bbox(&bbox);
    pyramid.set_zoom_min(10);
    pyramid.set_zoom_max(15);

    // Build conversion parameters
    let params = TilesConverterParameters {
        bbox_pyramid: Some(pyramid),
        tile_compression: Some(TileCompression::Gzip),
        ..Default::default()
    };

    // Perform the conversion
    convert_tiles_container(reader, params, output).await?;

    println!("Converted {} → {} with bbox and zoom limits", input, output);
    Ok(())
}

