fn canon_lower<'a>(o: Option<&'a str>) -> Cow<'a, str> {
    match o {
        None => Cow::Borrowed(""),
        Some(s) => {
            if s.chars().any(char::is_uppercase) {
                Cow::Owned(s.to_ascii_lowercase())
            } else {
                Cow::Borrowed(s)
            }
        }
    }
}

fn canon_script<'a>(o: Option<&'a str>) -> Cow<'a, str> {
    assert!(o.map_or(true, |s| s.len() >= 2 && &s[0..1] == "-"));
    match o {
        None => Cow::Borrowed(""),
        Some(s) => {
            if s[1..2].chars().next().unwrap().is_uppercase() && s[2..].chars().all(char::is_lowercase) {
                Cow::Borrowed(s)
            } else {
                Cow::Owned(format!("-{}{}", &s[1..2].to_ascii_uppercase(), s[2..].to_ascii_lowercase()))
            }
        }
    }
}

