    }

    pub fn from_unix(s: &str) -> Result<LanguageRange<'static>, crate::Error> {
        if let Some(caps) = UNIX_TAG_REGEX.captures(s) {
            let src_variant = caps.name("variant").map(|m| m.as_str()).unwrap_or("").to_ascii_lowercase();
            let mut res = caps.name("language").unwrap().as_str().to_ascii_lowercase();
            let region = caps.name("region").map(|m| m.as_str()).unwrap_or("");
            let mut script = "";
            let mut variant = "";
            let mut uvariant = "";
            match src_variant.as_ref() {
                "saaho" if res == "aa" => res = String::from("ssy"),
                "arabic" => script = "Arab",
                "cyrl" | "cyrillic" => script = "Cyrl",
                "devanagari" => script = "Deva",
                "hebrew" => script = "Hebr",
                "iqtelif" => script = "Latn",
                "latn" | "latin" => script = "Latn",
                "shaw" => script = "Shaw",
                "ijekavianlatin" => { script = "Latn"; variant = "ijekavsk"; },
                "ije" => variant = "ijekavsk",
                "ijekavian" => variant = "ijekavsk",
                "valencia" => variant = "valencia",
                "euro" => {},
                s if s.len() <= 8 => uvariant = s,
                s => uvariant = &s[0..8],
                _ => {}
            };
            if script != "" { res.push('-'); res.push_str(script); }
            if !region.is_empty() { res.push('-'); res.push_str(&region.to_ascii_uppercase()); }
            if variant != "" { res.push('-'); res.push_str(variant); }
            if uvariant != "" { res.push_str("-u-va-"); res.push_str(uvariant); }
