use writeable::Writeable;

struct CombinedMessage<'a> {
    parts: &'a [&'a str],
    separator: &'a str,
}

impl<'a> Writeable for CombinedMessage<'a> {
    fn write_to<W: std::fmt::Write + ?Sized>(&self, sink: &mut W) -> std::fmt::Result {
        for (i, &part) in self.parts.iter().enumerate() {
            if i > 0 {
                sink.write_str(self.separator)?;
            }
            sink.write_str(part)?;
        }
        Ok(())
    }

    fn writeable_length_hint(&self) -> writeable::LengthHint {
        let total_len: usize = self.parts.iter().map(|&s| s.len()).sum();
        let sep_len: usize = self.separator.len() * (self.parts.len().saturating_sub(1));
        writeable::LengthHint::exact(total_len + sep_len)
    }
}

