fn hash_file(path: &str) -> Result<String> {
    let mut file = File::open(path)?;
    let mut hasher = md5::default();
    let mut buffer = [0u8; 64];
    loop {
        let n = file.read(&mut buffer)?;
        if n == 0 { break; }
        hasher.update(&buffer[..n]);
    }
    Ok(hasher.digest().to_hex_lowercase())
}

