pub fn snake_or_kebab_case(s: &str, is_snake_case: bool) -> String {
    let mut result = String::new();
    for ch in s.chars() {
        if ch.is_ascii_uppercase() && !result.is_empty() {
            if is_snake_case {
                result.push('_');
            } else {
                result.push('-');
            }
        };

        if ch == '_' || ch == '-' {
