use std::fmt::{self, Display, Formatter};

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Signature {
    Unit,
    U8,
    Bool,
    I16,
    U16,
    I32,
    U32,
    I64,
    U64,
    F64,
    Str,
    Signature,
    ObjectPath,
    Variant,
    Array(Child),
    // other variants omitted for brevity
}

impl Signature {
    pub fn array<C>(child: C) -> Self
    where
        C: Into<Child>,
    {
        Signature::Array(child.into())
    }
}

impl Display for Signature {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        match self {
            Signature::Unit => write!(f, ""),
            Signature::U8 => write!(f, "y"),
            Signature::Bool => write!(f, "b"),
            Signature::I16 => write!(f, "n"),
            Signature::U16 => write!(f, "q"),
            Signature::I32 => write!(f, "i"),
            Signature::U32 => write!(f, "u"),
            Signature::I64 => write!(f, "x"),
            Signature::U64 => write!(f, "t"),
            Signature::F64 => write!(f, "d"),
            Signature::Str => write!(f, "s"),
            Signature::Signature => write!(f, "g"),
            Signature::ObjectPath => write!(f, "o"),
            Signature::Variant => write!(f, "v"),
            Signature::Array(child) => write!(f, "a{}", child),
        }
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Child {
    Static { child: &'static Signature },
    Dynamic { child: Box<Signature> },
}

impl From<&'static Signature> for Child {
    fn from(child: &'static Signature) -> Self {
        Child::Static { child }
    }
}

impl From<Signature> for Child {
    fn from(child: Signature) -> Self {
        Child::Dynamic { child: Box::new(child) }
    }
}

impl Display for Child {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        match self {
            Child::Static { child } => write!(f, "{}", child),
            Child::Dynamic { child } => write!(f, "{}", child),
        }
    }
}

