use nom::bytes::complete::tag;
use nom::IResult;
use nom_locate::{position, LocatedSpan};

type Span<'a> = LocatedSpan<&'a str>;

fn parse_word(s: Span) -> IResult<Span, usize> {
    let (s, _) = position(s)?;
    let (s, _) = tag("ジ")(s)?;
    Ok((s, s.get_utf8_column()))
}

fn main() {
    let input = Span::new("メカジキ");
    let (_, col) = parse_word(input).unwrap();
    println!("UTF‑8 column: {}", col);
}

