pub fn extract_html_props(context: &String) -> Vec<String> {
    let mut props = Vec::new();
    let mut current = String::new();
    let mut inside = false;
    for c in context.chars() {
        if inside {
            if c == '=' {
                props.push(current.trim().to_string());
                current.clear();
            } else if c != ' ' {
                current.push(c);
            }
        }
        if c == '<' {
            inside = true;
        }
        if c == '>' {
            inside = false;
        }
    }
    props.sort();
    props
}

