        Self { dst_line, dst_col, src_line, src_col, source_id, name_id }
    }
}

pub struct TokenChunk; // omitted for brevity

pub struct SourceMap {
    pub names: Vec<Arc<str>>,
    pub sources: Vec<Arc<str>>,
    pub source_contents: Vec<Option<Arc<str>>>,
    pub tokens: Vec<Token>,
    pub token_chunks: Option<Vec<TokenChunk>>,
}

impl SourceMap {
    pub fn get_tokens(&self) -> impl Iterator<Item = &Token> {
        self.tokens.iter()
    }
}

pub struct SourceMapBuilder {
    pub names_map: FxHashMap<Arc<str>, u32>,
    pub names: Vec<Arc<str>>,
    pub sources: Vec<Arc<str>>,
    pub sources_map: FxHashMap<Arc<str>, u32>,
    pub source_contents: Vec<Option<Arc<str>>>,
    pub tokens: Vec<Token>,
    pub token_chunks: Option<Vec<TokenChunk>>,
}

impl Default for SourceMapBuilder {
    fn default() -> Self {
        Self {
            names_map: FxHashMap::default(),
            names: Vec::new(),
            sources: Vec::new(),
            sources_map: FxHashMap::default(),
            source_contents: Vec::new(),
            tokens: Vec::new(),
            token_chunks: None,
        }
    }
}

impl SourceMapBuilder {
    pub fn add_name(&mut self, name: &str) -> u32 {
        let count = self.names.len() as u32;
        let id = *self.names_map.entry(name.into()).or_insert(count);
        if id == count { self.names.push(name.into()); }
        id
    }

    pub fn add_source_and_content(&mut self, source: &str, content: &str) -> u32 {
        let count = self.sources.len() as u32;
        let id = *self.sources_map.entry(source.into()).or_insert(count);
        if id == count {
            self.sources.push(source.into());
            self.source_contents.push(Some(content.into()));
        }
        id
    }

    pub fn add_token(&mut self, dst_line: u32, dst_col: u32, src_line: u32, src_col: u32, src_id: Option<u32>, name_id: Option<u32>) {
        self.tokens.push(Token::new(dst_line, dst_col, src_line, src_col, src_id, name_id));
    }

    pub fn into_sourcemap(self) -> SourceMap {
        SourceMap {
            names: self.names,
            sources: self.sources,
            source_contents: self.source_contents,
            tokens: self.tokens,
            token_chunks: self.token_chunks,
        }
    }
}

