    condvar: Condvar,
}

impl SharedChild {
    pub fn spawn(command: &mut Command) -> std::io::Result<Self> {
        Ok(SharedChild {
            inner: Mutex::new(SharedChildInner {
                child: command.spawn()?,
                state: ChildState::NotWaiting,
            }),
            condvar: Condvar::new(),
        })
    }

    pub fn wait(&self) -> std::io::Result<ExitStatus> {
        unimplemented!()
    }

    #[cfg(feature = "timeout")]
    pub fn wait_timeout(&self, _duration: std::time::Duration) -> std::io::Result<Option<ExitStatus>> {
        unimplemented!()
    }

    pub fn kill(&self) -> std::io::Result<()> {
        self.inner.lock().unwrap().child.kill()
    }

    pub fn take_stdout(&self) -> Option<ChildStdout> {
        self.inner.lock().unwrap().child.stdout.take()
    }
}

#[cfg(unix)]
pub trait SharedChildExt {
    fn send_signal(&self, signal: libc::c_int) -> std::io::Result<()>;
}

#[cfg(unix)]
impl SharedChildExt for SharedChild {
    fn send_signal(&self, signal: libc::c_int) -> std::io::Result<()> {
        let guard = self.inner.lock().unwrap();
        if let ChildState::Exited(_) = guard.state {
            return Ok(());
        }
        let pid = guard.child.id() as libc::pid_t;
        let res = unsafe { libc::kill(pid, signal) };
        if res == -1 {
            Err(std::io::Error::last_os_error())
        } else {
            Ok(())
        }
    }
}

