use std::sync::Arc;
use std::os::raw::c_void;

pub const RANDOMX_HASH_SIZE: u32 = 32;

pub type randomx_flags = ::std::os::raw::c_uint;

#[repr(C)]
pub struct randomx_cache { _unused: [u8; 0] }
#[repr(C)]
pub struct randomx_dataset { _unused: [u8; 0] }
#[repr(C)]
pub struct randomx_vm { _unused: [u8; 0] }

extern "C" {
    fn randomx_get_flags() -> randomx_flags;
    fn randomx_alloc_cache(flags: randomx_flags) -> *mut randomx_cache;
    fn randomx_init_cache(cache: *mut randomx_cache, key: *const c_void, keySize: usize);
    fn randomx_release_cache(cache: *mut randomx_cache);
    fn randomx_create_vm(flags: randomx_flags, cache: *mut randomx_cache, dataset: *mut randomx_dataset) -> *mut randomx_vm;
    fn randomx_calculate_hash(vm: *mut randomx_vm, input: *const c_void, inputSize: usize, output: *mut c_void);
    fn randomx_destroy_vm(vm: *mut randomx_vm);
}

pub struct Context {
    key: Vec<u8>,
    flags: randomx_flags,
    fast: bool,
    cache: *mut randomx_cache,
    dataset: *mut randomx_dataset,
}

impl Context {
    pub fn new(key: &[u8], fast: bool) -> Self {
        unsafe {
            let mut flags = randomx_get_flags();
            let mut cache = randomx_alloc_cache(flags);
            randomx_init_cache(cache, key.as_ptr() as *const c_void, key.len());
            let dataset = std::ptr::null_mut();
            Self { key: key.to_vec(), flags, fast, cache, dataset }
        }
    }
}

pub struct Hasher {
    vm: *mut randomx_vm,
}

impl Hasher {
    pub fn new(context: Arc<Context>) -> Self {
        unsafe {
            let vm = randomx_create_vm(context.flags, context.cache, context.dataset);
            Self { vm }
        }
    }
    pub fn hash(&self, inp: &[u8]) -> Output {
        let mut hash = [0u8; RANDOMX_HASH_SIZE as usize];
        unsafe {
            randomx_calculate_hash(self.vm, inp.as_ptr() as *const c_void, inp.len(), hash.as_mut_ptr() as *mut c_void);
        }
        Output(hash)
    }
}

impl Drop for Hasher {
    fn drop(&mut self) {
        unsafe { randomx_destroy_vm(self.vm); }
    }
}

pub struct Output([u8; RANDOMX_HASH_SIZE as usize]);

impl AsRef<[u8]> for Output {
    fn as_ref(&self) -> &[u8] { &self.0 }
}

