use zvariant_utils::case::pascal_or_camel_case;

fn pascal_or_camel_case(s: &str, is_pascal_case: bool) -> String {
    let mut result = String::new();
    let mut capitalize = is_pascal_case;
    let mut first = true;
    for ch in s.chars() {
        if ch == '_' || ch == '-' {
            capitalize = true;
        } else if capitalize {
            result.push(ch.to_ascii_uppercase());
            capitalize = false;
        } else if first && !is_pascal_case {
            result.push(ch.to_ascii_lowercase());
        } else {
            result.push(ch);
        }
        if first {
            first = false;
        }
    }
    result
}

