use std::io;
use std::process::{Child, ExitStatus};
use std::sync::{Condvar, Mutex, MutexGuard};

#[derive(Debug)]
enum ChildState {
    NotWaiting,
    Waiting,
    Exited(ExitStatus),
}

struct SharedChildInner {
    child: Child,
    state: ChildState,
}

pub struct SharedChild {
    inner: Mutex<SharedChildInner>,
    condvar: Condvar,
}

impl SharedChild {
    pub fn spawn(command: &mut std::process::Command) -> io::Result<Self> {
        Ok(SharedChild {
            inner: Mutex::new(SharedChildInner {
                child: command.spawn()?,
                state: ChildState::NotWaiting,
            }),
            condvar: Condvar::new(),
        })
    }

    pub fn kill(&self) -> io::Result<()> {
        self.inner.lock().unwrap().child.kill()
    }

    pub fn wait(&self) -> io::Result<ExitStatus> {
        let mut inner_guard = self.inner.lock().unwrap();
        loop {
            match inner_guard.state {
                ChildState::Exited(exit_status) => return Ok(exit_status),
                ChildState::Waiting => inner_guard = self.condvar.wait(inner_guard).unwrap(),
                ChildState::NotWaiting => break,
            }
        }
        inner_guard.state = ChildState::Waiting;
        let handle = sys::get_handle(&inner_guard.child);
        drop(inner_guard);
        sys::wait_noreap(handle)?;
        let mut inner_guard = self.inner.lock().unwrap();
        inner_guard.state = ChildState::NotWaiting;
        self.condvar.notify_all();
        let exit_status = inner_guard.child.wait()?;
        inner_guard.state = ChildState::Exited(exit_status);
        Ok(exit_status)
    }
}

mod sys {
    #[cfg(unix)]
    mod unix {
        use std::io;
        use std::process::Child;
        #[derive(Copy, Clone)]
        pub struct Handle(u32);
        pub fn get_handle(child: &Child) -> Handle {
            Handle(child.id())
        }
        pub fn wait_noreap(_handle: Handle) -> io::Result<()> {
            // Platform‑specific implementation omitted for brevity
            Ok(())
        }
    }
    #[cfg(unix)]
    pub use unix::*;
}

pub mod unix {
    use std::io;
    use super::SharedChild;
    use super::ChildState;
    pub trait SharedChildExt {
        fn send_signal(&self, signal: libc::c_int) -> io::Result<()>;
    }
    impl SharedChildExt for SharedChild {
        fn send_signal(&self, signal: libc::c_int) -> io::Result<()> {
            let inner_guard = self.inner.lock().unwrap();
            if let ChildState::Exited(_) = inner_guard.state {
                return Ok(());
            }
            let pid = inner_guard.child.id() as libc::pid_t;
            match unsafe { libc::kill(pid, signal) } {
                -1 => Err(io::Error::last_os_error()),
                _ => Ok(()),
            }
        }
    }
}

