enum PathValue {
    Normal(u32),
    Hardened(u32),
}

impl PathValue {
    fn is_ok(v: u32) -> bool {
        v < 0x80000000
    }
}

enum Purpose {
    Pubkey,
    ScriptHash,
    Witness,
    Custom(u32),
}

impl Purpose {
    fn as_value(&self) -> PathValue {
        match self {
            Purpose::Pubkey => PathValue::Hardened(44),
            Purpose::ScriptHash => PathValue::Hardened(49),
            Purpose::Witness => PathValue::Hardened(84),
            Purpose::Custom(n) => PathValue::Hardened(*n),
        }
    }
}

struct StandardHDPath {
    purpose: Purpose,
    coin_type: u32,
    account: u32,
    change: u32,
    index: u32,
}

impl StandardHDPath {
    fn new(purpose: Purpose, coin_type: u32, account: u32, change: u32, index: u32) -> Self {
        StandardHDPath { purpose, coin_type, account, change, index }
    }
}

impl std::fmt::Display for StandardHDPath {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        let purpose_num = match self.purpose {
            Purpose::Pubkey => 44,
            Purpose::ScriptHash => 49,
            Purpose::Witness => 84,
            Purpose::Custom(n) => n,
        };
        write!(f, "m/{}'/{}'/{}'/{}/{}", purpose_num, self.coin_type, self.account, self.change, self.index)
    }
}

