unsafe fn get_string_arg(env: napi_env, arg: napi_value) -> Result<String, u32> {
    let mut length: usize = 0;
    let status = napi_get_value_string_utf8(env, arg, std::ptr::null_mut(), 0, &mut length);
    if status != 0 { return Err(status); }
    let mut buffer = Vec::with_capacity(length + 1);
    let status = napi_get_value_string_utf8(
        env,
        arg,
        buffer.as_mut_ptr() as *mut std::os::raw::c_char,
        length + 1,
        &mut length,
    );
    if status != 0 { return Err(status); }
    buffer.set_len(length);
    Ok(String::from_utf8_unchecked(buffer))
}

