pub struct SourceType {
    language: Language,
    module_kind: ModuleKind,
    variant: LanguageVariant,
}

#[derive(Clone, Copy, PartialEq, Eq, Hash)]
pub enum Language {
    JavaScript = 0,
    TypeScript = 1,
    TypeScriptDefinition = 2,
}

#[derive(Clone, Copy, PartialEq, Eq, Hash)]
pub enum ModuleKind {
    Script = 0,
    Module = 1,
    Unambiguous = 2,
}

#[derive(Clone, Copy, PartialEq, Eq, Hash)]
pub enum LanguageVariant {
    Standard = 0,
    Jsx = 1,
}

impl SourceType {
    pub const fn ts() -> Self {
        Self { language: Language::TypeScript, module_kind: ModuleKind::Module, variant: LanguageVariant::Standard }
    }
    pub const fn tsx() -> Self {
        Self::ts().with_jsx(true)
    }
    pub const fn with_jsx(mut self, yes: bool) -> Self {
        if yes { self.variant = LanguageVariant::Jsx; }
        self
    }
    pub fn is_typescript(&self) -> bool {
        matches!(self.language, Language::TypeScript | Language::TypeScriptDefinition)
    }
    pub fn is_jsx(&self) -> bool {
        self.variant == LanguageVariant::Jsx
    }
}

