pub struct ByteBuffer<'a> {
    data: &'a [u8],
    index: usize,
}

impl<'a> ByteBuffer<'a> {
    pub fn new(data: &[u8]) -> ByteBuffer {
        ByteBuffer { data, index: 0 }
    }
    pub fn read_byte(&mut self) -> Result<u8, ()> {
        if self.index >= self.data.len() { Err(()) } else { let v = self.data[self.index]; self.index += 1; Ok(v) }
    }
    pub fn read_var_uint(&mut self) -> Result<u32, ()> {
        let mut shift: u8 = 0;
        let mut result: u32 = 0;
        loop {
            let byte = self.read_byte()?;
            result |= ((byte & 127) as u32) << shift;
            shift += 7;
            if (byte & 128) == 0 || shift >= 35 { break; }
        }
        Ok(result)
    }
    pub fn read_var_int(&mut self) -> Result<i32, ()> {
        let value = self.read_var_uint()?;
        Ok(if (value & 1) != 0 { !(value >> 1) } else { value >> 1 } as i32)
    }
}

