pub const TYPE_FLOAT: i32 = -5;

pub struct Schema {
    defs: Vec<()>,
}

impl Schema {
    pub fn new(defs: Vec<()>) -> Schema { Schema { defs } }
    pub fn skip(&self, bb: &mut ByteBuffer, type_id: i32) -> Result<(), ()> {
        self.skip_with_options(bb, type_id, &SchemaOptions { validate_enums: true })
    }
    pub fn skip_with_options(&self, bb: &mut ByteBuffer, type_id: i32, _options: &SchemaOptions) -> Result<(), ()> {
        match type_id {
            TYPE_FLOAT => { bb.read_var_float()?; Ok(()) },
            _ => Err(()),
        }
    }
}

pub struct SchemaOptions {
    pub validate_enums: bool,
}

pub struct ByteBuffer<'a> {
    data: &'a [u8],
    index: usize,
}

impl<'a> ByteBuffer<'a> {
    pub fn new(data: &[u8]) -> ByteBuffer { ByteBuffer { data, index: 0 } }
    pub fn index(&self) -> usize { self.index }
    pub fn read_byte(&mut self) -> Result<u8, ()> {
        if self.index >= self.data.len() { Err(()) } else { let v = self.data[self.index]; self.index += 1; Ok(v) }
    }
    pub fn read_var_float(&mut self) -> Result<f32, ()> {
        let first = self.read_byte()?;
        if first == 0 { return Ok(0.0); }
        if self.index + 3 > self.data.len() { return Err(()); }
        let mut bits: u32 = first as u32
            | ((self.data[self.index] as u32) << 8)
            | ((self.data[self.index + 1] as u32) << 16)
            | ((self.data[self.index + 2] as u32) << 24);
        self.index += 3;
        bits = (bits << 23) | (bits >> 9);
        Ok(f32::from_bits(bits))
    }
}

