pub enum SpanState {
    Real { span: SpanBuilder, start_instant: std::time::Instant },
    Nop,
}

pub struct SpanBuilder;

impl SpanBuilder {
    pub fn annotation(&mut self, _a: Annotation) {}
}

pub struct OpenSpan<T> {
    _mode: T,
    context: zipkin::TraceContext,
    state: SpanState,
}

impl<T> OpenSpan<T> {
    pub fn annotate(&mut self, value: &str) {
        if let SpanState::Real { span, .. } = &mut self.state {
            let annotation = Annotation::now(value);
            span.annotation(annotation);
        }
    }
}

