pub struct RouteHint;

pub struct PrunedInvoice {
    pub amount: Amount,
    pub destination: secp256k1::PublicKey,
    pub destination_features: Vec<u8>,
    pub payment_hash: sha256::Hash,
    pub payment_secret: [u8; 32],
    pub route_hints: Vec<RouteHint>,
    pub min_final_cltv_delta: u64,
    pub expiry_timestamp: u64,
}

impl PrunedInvoice {
    pub fn new(invoice: &lightning_invoice::Bolt11Invoice, amount: Amount) -> Self {
        let destination = secp256k1::PublicKey::from_slice(&[0u8; 33]).unwrap();
        let payment_hash = sha256::Hash::hash(&[0u8]);
        let payment_secret = [0u8; 32];
        let route_hints = Vec::new();
        let destination_features = Vec::new();
        let min_final_cltv_delta = invoice.min_final_cltv_expiry_delta();
        let expiry_timestamp = invoice.expires_at().map_or(u64::MAX, |t| t.as_secs());
        PrunedInvoice {
            amount,
            destination,
            destination_features,
            payment_hash,
            payment_secret,
            route_hints,
            min_final_cltv_delta,
            expiry_timestamp,
        }
    }
}

use std::convert::TryFrom;
use anyhow::Error;
impl TryFrom<lightning_invoice::Bolt11Invoice> for PrunedInvoice {
    type Error = Error;
    fn try_from(invoice: lightning_invoice::Bolt11Invoice) -> Result<Self, Self::Error> {
        let amount = Amount::from_msats(
            invoice.amount_milli_satoshis().ok_or_else(|| anyhow::anyhow!("Invoice amount is missing"))?
        );
        Ok(PrunedInvoice::new(&invoice, amount))
    }
}

