pub trait IntoNanoseconds {
    fn into_nanos(self) -> u64;
}
impl IntoNanoseconds for u64 {
    fn into_nanos(self) -> u64 { self }
}
impl IntoNanoseconds for std::time::Duration {
    fn into_nanos(self) -> u64 { self.as_nanos() as u64 }
}

pub struct Mock {
    offset: std::sync::Arc<crossbeam_utils::atomic::AtomicCell<u64>>,
}
impl Mock {
    pub fn new() -> Self {
        Self { offset: std::sync::Arc::new(crossbeam_utils::atomic::AtomicCell::new(0)) }
    }
    pub fn increment<N: IntoNanoseconds>(&self, amount: N) {
        let amount = amount.into_nanos();
        self.offset.fetch_update(|c| Some(c + amount)).unwrap();
    }
    pub fn decrement<N: IntoNanoseconds>(&self, amount: N) {
        let amount = amount.into_nanos();
        self.offset.fetch_update(|c| Some(c - amount)).unwrap();
    }
    pub fn value(&self) -> u64 { self.offset.load() }
}

impl Clock {
    pub fn mock() -> (Clock, std::sync::Arc<Mock>) {
        let mock = std::sync::Arc::new(Mock::new());
        (Clock, mock)
    }
}

