extern crate alloc;
use alloc::vec::Vec;
use core::mem;

pub struct NonEmpty<T> {
    pub head: T,
    pub tail: Vec<T>,
}

impl<T> NonEmpty<T> {
    pub const fn new(e: T) -> Self { Self::singleton(e) }
    pub const fn singleton(head: T) -> Self { NonEmpty { head, tail: Vec::new() } }
    pub fn insert(&mut self, index: usize, element: T) {
        let len = self.tail.len() + 1;
        assert!(index <= len);
        if index == 0 {
            let head = mem::replace(&mut self.head, element);
            self.tail.insert(0, head);
        } else {
            self.tail.insert(index - 1, element);
        }
    }
    pub fn from_vec(mut vec: Vec<T>) -> Option<NonEmpty<T>> {
        if vec.is_empty() { None } else { let head = vec.remove(0); Some(NonEmpty { head, tail: vec }) }
    }
    pub fn from(pair: (T, Vec<T>)) -> Self { NonEmpty { head: pair.0, tail: pair.1 } }
}

impl<T> From<(T, Vec<T>)> for NonEmpty<T> {
    fn from((head, tail): (T, Vec<T>)) -> Self { NonEmpty { head, tail } }
}

