extern crate alloc;
use alloc::vec::Vec;
use core::mem;

pub struct NonEmpty<T> {
    pub head: T,
    pub tail: Vec<T>,
}

impl<T> NonEmpty<T> {
    pub const fn new(e: T) -> Self { Self::singleton(e) }
    pub const fn singleton(head: T) -> Self { NonEmpty { head, tail: Vec::new() } }
    pub fn maximum(&self) -> &T where T: Ord {
        let mut max = &self.head;
        for e in &self.tail {
            if e > max { max = e; }
        }
        max
    }
    pub fn from_vec(mut vec: Vec<T>) -> Option<NonEmpty<T>> {
        if vec.is_empty() { None } else { let head = vec.remove(0); Some(NonEmpty { head, tail: vec }) }
    }
}

#[macro_export]
macro_rules! nonempty {
    ($h:expr, $( $x:expr ),* $(,)?) => {{
        let tail = vec![$($x),*];
        $crate::NonEmpty { head: $h, tail }
    }};
    ($h:expr) => {{
        $crate::NonEmpty { head: $h, tail: alloc::vec::Vec::new() }
    }};
}

