use chia_bls::{PublicKey, SecretKey};
use chia_sha2::Sha256;
use hex_literal::hex;
use num_bigint::BigInt;
use clvm_traits::{ToClvm, FromClvm};

const GROUP_ORDER_BYTES: [u8; 32] = hex!("73eda753299d7d483339d80809a1d80553bda402fffe5bfeffffffff00000001");

pub trait DeriveSynthetic {
    fn derive_synthetic_hidden(&self, hidden_puzzle_hash: &[u8; 32]) -> Self;
    fn derive_synthetic(&self) -> Self where Self: Sized {
        self.derive_synthetic_hidden(&DEFAULT_HIDDEN_PUZZLE_HASH)
    }
}

impl DeriveSynthetic for PublicKey {
    fn derive_synthetic_hidden(&self, hidden_puzzle_hash: &[u8; 32]) -> Self {
        self + &synthetic_offset(self, hidden_puzzle_hash).public_key()
    }
}

pub fn synthetic_offset(public_key: &PublicKey, hidden_puzzle_hash: &[u8; 32]) -> SecretKey {
    let mut hasher = Sha256::new();
    hasher.update(public_key.to_bytes());
    hasher.update(hidden_puzzle_hash);
    let bytes: [u8; 32] = hasher.finalize().into();
    SecretKey::from_bytes(&mod_by_group_order(bytes)).unwrap()
}

pub fn mod_by_group_order(bytes: [u8; 32]) -> [u8; 32] {
    let value = BigInt::from_signed_bytes_be(&bytes);
    let group_order = BigInt::from_signed_bytes_be(&GROUP_ORDER_BYTES);
    let modulo = ((value % &group_order) + &group_order) % &group_order;
    let mut vec = modulo.to_bytes_be().1;
    if vec.len() < 32 {
        let mut pad = vec![0u8; 32 - vec.len()];
        pad.append(&mut vec);
        vec = pad;
    }
    vec.try_into().unwrap()
}

const DEFAULT_HIDDEN_PUZZLE_HASH: [u8; 32] = [0u8; 32];

