use proc_macro2::Ident;
use proc_macro2::Span;
use std::fmt::{Display, Formatter, Result as FmtResult};

#[derive(Clone, Debug, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub struct TypePath {
    parts: Vec<Ident>,
    is_absolute: bool,
}

impl TypePath {
    pub fn new(path: &str) -> std::result::Result<Self, String> {
        let is_absolute = Self::is_absolute(path);
        let parts: Vec<Ident> = path
            .split("::")
            .skip(if is_absolute { 1 } else { 0 })
            .map(|p| Ident::new(p.trim(), Span::call_site()))
            .collect();
        Ok(Self { parts, is_absolute })
    }

    fn is_absolute(path: &str) -> bool {
        path.trim_start().starts_with("::")
    }
}

impl Display for TypePath {
    fn fmt(&self, f: &mut Formatter<'_>) -> FmtResult {
        let prefix = if self.is_absolute { "::" } else { "" };
        let joined = self.parts.iter().map(|i| i.to_string()).collect::<Vec<_>>().join("::");
        write!(f, "{}{}", prefix, joined)
    }
}

