use std::path::PathBuf;
use std::fs::File;
use std::io::Read;
use std::io::Write;
use regex::Regex;
use crate::tokenizer::Tokenizer;
use crate::parser::Parser;
use crate::optimizer;
use crate::context::Context;
use crate::error::Result;
pub fn compile(input_filename: &str, output: &mut Write, style: &str) -> Result<()> {
    let input_path = PathBuf::from(input_filename);
    let imports_resolved = resolve_imports(&input_path)?;
    match style {
        "tokens" => {
            let mut tokenizer = Tokenizer::new(&imports_resolved);
            while let Some(token) = tokenizer.next() {
                writeln!(output, "{:?}", token?);
            }
        },
        "ast" => {
            let mut parser = Parser::new(&imports_resolved);
            while let Some(root) = parser.next() {
                writeln!(output, "{:#?}", root?);
            }
        },
        other => {
            let style_box: Box<dyn SassOutputStyle> = get_style(other);
            let mut parser = Parser::new(&imports_resolved);
            let mut context = Context::new();
            while let Some(Ok(ast_root)) = parser.next() {
                if let Some(evaluated) = ast_root.evaluate(&mut context) {
                    let optimized = optimizer::optimize(evaluated);
                    for r in optimized {
                        r.stream(output, &*style_box)?;
                    }
                }
            }
        }
    }
    Ok(())
}
fn resolve_imports(inputpath: &PathBuf) -> Result<String> {
    let mut file = File::open(&inputpath)?;
    let mut sass = String::new();
    file.read_to_string(&mut sass)?;
    let mut imports_resolved = String::new();
    for line in sass.split("\n") {
        let re = Regex::new("@import \"([^\"]*)\";").unwrap();
        if let Some(caps) = re.captures(line) {
            let imported = resolve_imports(&inputpath.with_file_name(caps.get(1).unwrap().as_str()))?;
            imports_resolved.push_str(&imported);
        } else {
            imports_resolved.push_str(line);
        }
        imports_resolved.push_str("\n");
    }
    Ok(imports_resolved)
}
trait SassOutputStyle {
    fn rule_separator(&self) -> String { String::from("\n\n") }
    fn selector_separator(&self) -> String { String::from(", ") }
    fn selector_string(&self, _rule: &SassRule, _parents: &str) -> String { String::new() }
    fn selector_brace_separator(&self) -> String { String::from(" ") }
    fn brace_property_separator(&self) -> String { String::from("") }
    fn before_property(&self, _nesting: &str) -> String { String::from("\n") }
    fn after_property(&self) -> String { String::from("") }
    fn property_brace_separator(&self) -> String { String::from("") }
    fn rule_and_child_rules_separator(&self, _nesting: &str) -> String { String::from("") }
    fn child_rule_separator(&self, _has_properties: bool) -> String { String::from("\n") }
    fn property(&self, name: &str, value: &str) -> String { format!("  {}: {};", name, value) }
    fn before_comment(&self) -> String { String::new() }
    fn comment(&self, content: &str) -> String { String::from(content) }
    fn after_comment(&self) -> String { String::from("\n") }
}
struct Compressed;
impl SassOutputStyle for Compressed {
    fn rule_separator(&self) -> String { String::from("") }
    fn selector_separator(&self) -> String { String::from(",") }
    fn selector_brace_separator(&self) -> String { String::from("") }
    fn before_property(&self, _nesting: &str) -> String { String::from("") }
    fn after_property(&self) -> String { String::from(";") }
    fn child_rule_separator(&self, _has_properties: bool) -> String { String::from("") }
    fn property(&self, name: &str, value: &str) -> String { format!("{}:{}", name, value) }
    fn comment(&self, _content: &str) -> String { String::new() }
    fn after_comment(&self) -> String { String::new() }
}
fn get_style(style: &str) -> Box<dyn SassOutputStyle> {
    match style {
        "compressed" => Box::new(Compressed {}),
        _ => panic!("unknown style"),
    }
}
struct SassRule;

