pub struct StandardMarkers<'a> {
    other_name: Option<&'a str>,
    this_name: Option<&'a str>,
}

impl<'a> StandardMarkers<'a> {
    pub fn new(other_name: Option<&'a str>, this_name: Option<&'a str>) -> Self {
