use core::{alloc::{GlobalAlloc, Layout}, ptr::NonNull};

extern crate snmalloc_sys as ffi;

#[derive(Debug, Copy, Clone)]
#[repr(C)]
pub struct SnMalloc;

unsafe impl Send for SnMalloc {}
unsafe impl Sync for SnMalloc {}

impl SnMalloc {
    #[inline(always)]
    pub const fn new() -> Self { Self }

    #[inline(always)]
    pub fn usable_size(&self, ptr: *const u8) -> Option<usize> {
        if ptr.is_null() {
            None
        } else {
            Some(unsafe { ffi::sn_rust_usable_size(ptr.cast()) })
        }
    }
}

unsafe impl GlobalAlloc for SnMalloc {
    #[inline(always)]
    unsafe fn alloc(&self, layout: Layout) -> *mut u8 {
        if layout.size() == 0 {
            layout.align() as *mut u8
        } else {
            ffi::sn_rust_alloc(layout.align(), layout.size()).cast()
        }
    }

    #[inline(always)]
    unsafe fn dealloc(&self, ptr: *mut u8, layout: Layout) {
        if layout.size() != 0 {
            ffi::sn_rust_dealloc(ptr as _, layout.align(), layout.size());
        }
    }

    #[inline(always)]
    unsafe fn alloc_zeroed(&self, layout: Layout) -> *mut u8 {
        if layout.size() == 0 {
            layout.align() as *mut u8
        } else {
            ffi::sn_rust_alloc_zeroed(layout.align(), layout.size()).cast()
        }
    }

    #[inline(always)]
    unsafe fn realloc(&self, ptr: *mut u8, layout: Layout, new_size: usize) -> *mut u8 {
        if new_size == 0 {
            self.dealloc(ptr, layout);
            layout.align() as *mut u8
        } else if layout.size() == 0 {
            self.alloc(Layout::from_size_align_unchecked(new_size, layout.align()))
        } else {
            ffi::sn_rust_realloc(ptr.cast(), layout.align(), layout.size(), new_size).cast()
        }
    }
}

