use sigma_ser::ScorexSerializable;

impl<T: ScorexSerializable> ScorexSerializable for Vec<T> {
    fn scorex_serialize<W: sigma_ser::WriteSigmaVlqExt>(&self, w: &mut W) -> sigma_ser::ScorexSerializeResult {
        w.put_u32(self.len() as u32)?;
        self.iter().try_for_each(|i| i.scorex_serialize(w))
    }

    fn scorex_parse<R: sigma_ser::ReadSigmaVlqExt>(r: &mut R) -> Result<Self, sigma_ser::ScorexParsingError> {
        let items_count = r.get_u32()?;
        let mut items = Vec::with_capacity(items_count as usize);
        for _ in 0..items_count {
            items.push(T::scorex_parse(r)?);
        }
        Ok(items)
    }
}

