pub const LINE_TYPE_ADDED: &'static str = "+";
pub const LINE_TYPE_REMOVED: &'static str = "-";
pub const LINE_TYPE_CONTEXT: &'static str = " ";
pub const LINE_TYPE_EMPTY: &'static str = "\n";

#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub enum Error { TargetWithoutSource(String), UnexpectedHunk(String), ExpectLine(String) }
impl fmt::Display for Error { fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result { match *self { Error::TargetWithoutSource(ref l) => write!(f, "Target without source: {}", l), Error::UnexpectedHunk(ref l) => write!(f, "Unexpected hunk found: {}", l), Error::ExpectLine(ref l) => write!(f, "Hunk line expected: {}", l), } } }
impl error::Error for Error { fn description(&self) -> &str { match *self { Error::TargetWithoutSource(_) => "Target without source", Error::UnexpectedHunk(_) => "Unexpected hunk found", Error::ExpectLine(_) => "Hunk line expected", } } }
pub type Result<T> = ::std::result::Result<T, Error>;

#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct Line { pub source_line_no: Option<usize>, pub target_line_no: Option<usize>, pub diff_line_no: usize, pub line_type: String, pub value: String }
impl Line { pub fn new<T: Into<String>>(value: T, line_type: T) -> Line { Line { source_line_no: Some(0usize), target_line_no: Some(0usize), diff_line_no: 0usize, line_type: line_type.into(), value: value.into() } }
    pub fn is_added(&self) -> bool { LINE_TYPE_ADDED == &self.line_type }
    pub fn is_removed(&self) -> bool { LINE_TYPE_REMOVED == &self.line_type }
    pub fn is_context(&self) -> bool { LINE_TYPE_CONTEXT == &self.line_type }
}
impl fmt::Display for Line { fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result { write!(f, "{}{}", self.line_type, self.value) } }

#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct Hunk { added: usize, removed: usize, pub source_start: usize, pub source_length: usize, pub target_start: usize, pub target_length: usize, pub section_header: String, lines: Vec<Line>, source: Vec<String>, target: Vec<String> }
impl Hunk { pub fn new<T: Into<String>>(source_start: usize, source_length: usize, target_start: usize, target_length: usize, section_header: T) -> Hunk { Hunk { added: 0, removed: 0, source_start, source_length, target_start, target_length, section_header: section_header.into(), lines: vec![], source: vec![], target: vec![] } }
    pub fn added(&self) -> usize { self.added }
    pub fn removed(&self) -> usize { self.removed }
    pub fn is_valid(&self) -> bool { self.source.len() == self.source_length && self.target.len() == self.target_length }
    pub fn source_lines(&self) -> Vec<Line> { self.lines.iter().cloned().filter(|l| l.is_context() || l.is_removed()).collect() }
    pub fn target_lines(&self) -> Vec<Line> { self.lines.iter().cloned().filter(|l| l.is_context() || l.is_added()).collect() }
    pub fn append(&mut self, line: Line) { if line.is_added() { self.added += 1; self.target.push(format!("{}{}", line.line_type, line.value)); } else if line.is_removed() { self.removed += 1; self.source.push(format!("{}{}", line.line_type, line.value)); } else if line.is_context() { self.source.push(format!("{}{}", line.line_type, line.value)); self.target.push(format!("{}{}", line.line_type, line.value)); } self.lines.push(line); }
    pub fn len(&self) -> usize { self.lines.len() }
    pub fn is_empty(&self) -> bool { self.lines.is_empty() }
}
impl fmt::Display for Hunk { fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result { let header = format!("@@ -{},{} +{},{} @@ {}", self.source_start, self.source_length, self.target_start, self.target_length, self.section_header); let content = self.lines.iter().map(|l| l.to_string()).collect::<Vec<String>>().join("\n"); write!(f, "{}\n{}", header, content) } }
impl IntoIterator for Hunk { type Item = Line; type IntoIter = ::std::vec::IntoIter<Line>; fn into_iter(self) -> Self::IntoIter { self.lines.into_iter() } }
impl Index<usize> for Hunk { type Output = Line; fn index(&self, idx: usize) -> &Line { &self.lines[idx] } }
impl IndexMut<usize> for Hunk { fn index_mut(&mut self, index: usize) -> &mut Line { &mut self.lines[index] } }

