use std::{io, io::prelude::*};
use popol::{Sources, Timeout};

fn main() -> io::Result<()> {
    let mut sources = Sources::with_capacity(1);
    let mut events = Vec::with_capacity(1);

    sources.register((), &io::stdin(), popol::interest::READ);

    match sources.poll(&mut events, Timeout::from_secs(5)) {
        Ok(_) => {}
        Err(e) if e.kind() == io::ErrorKind::TimedOut => {
            eprintln!("No input within 5 seconds");
            return Ok(());
        }
        Err(e) => return Err(e),
    }

    for event in events.drain(..) {
        if event.is_readable() || event.is_hangup() {
            let mut buf = [0u8; 1024];
            let n = io::stdin().read(&mut buf)?;
            io::stdout().write_all(&buf[..n])?;
        }
    }

    Ok(())
}

use std::{thread, time::Duration};
use popol::{Sources, Waker, Timeout};

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut events = Vec::new();
    let mut sources = Sources::new();

    let waker = Waker::register(&mut sources, "waker")?;

    let handle = thread::spawn(move || {
        thread::sleep(Duration::from_millis(200));
        waker.wake().expect("wake failed");
    });

    sources.poll(&mut events, Timeout::from_secs(1))?;

    assert!(!events.is_empty(), "expected waker event");
    let event = &events[0];
    assert_eq!(event.key, "waker");
    assert!(event.is_readable(), "waker should be readable");

    handle.join().unwrap();
    Ok(())
}

