        match self {
            Message::A(v) => &v.x,
            Message::B(v) => &v.x,
        }
    }
    pub fn y(&self) -> Result<&String, ()> {
        match self {
            Message::B(v) => Ok(&v.y),
            _ => Err(()),
        }
    }
}

impl<'a> MessageRef<'a> {
    pub fn x(&self) -> &String {
        match self {
