impl SugarPath for Path {
    fn normalize(&self) -> PathBuf {
        let mut components = to_normalized_components(self);
        if components.is_empty() {
            return PathBuf::from(".");
        }
        if cfg!(target_family = "windows") {
            if components.len() == 1 && matches!(components[0], Component::Prefix(_)) {
                components.push(Component::CurDir)
            }
        }
        components.into_iter().collect()
    }

    fn absolutize(&self) -> PathBuf {
        self.absolutize_with(get_current_dir())
    }

    fn absolutize_with<'a>(&self, base: impl IntoCowPath<'a>) -> PathBuf {
        let base: Cow<'a, Path> = base.into_cow_path();
        let mut base = if base.is_absolute() { base } else { Cow::Owned(base.absolutize()) };
        if self.is_absolute() {
            self.normalize()
        } else if cfg!(target_family = "windows") {
            let mut components = self.components();
            if matches!(components.next(), Some(Component::Prefix(_))) && !matches!(components.next(), Some(Component::RootDir)) {
                let mut comps = self.components().into_iter().collect::<Vec<_>>();
                comps.insert(1, Component::RootDir);
                component_vec_to_path_buf(comps).normalize()
            } else {
                base.to_mut().push(self);
                base.normalize()
            }
        } else {
            base.to_mut().push(self);
            base.normalize()
        }
    }

    fn relative(&self, to: impl AsRef<Path>) -> PathBuf {
        let base = to.as_ref().absolutize();
        let target = self.absolutize();
        if base == target {
            PathBuf::new()
        } else {
            let base_components = base.components().filter(|c| matches!(c, Component::Normal(_) | Component::Prefix(_) | Component::RootDir)).collect::<Vec<_>>();
            let target_components = target.components().filter(|c| matches!(c, Component::Normal(_) | Component::Prefix(_) | Component::RootDir)).collect::<Vec<_>>();
            let mut ret = PathBuf::new();
            let mut i = 0;
            while i < base_components.len().max(target_components.len()) {
                let from = base_components.get(i);
                let to_c = target_components.get(i);
                if cfg!(target_family = "windows") {
                    if let (Some(Component::Normal(f)), Some(Component::Normal(t))) = (from, to_c) {
                        if f.to_ascii_lowercase() == t.to_ascii_lowercase() {
                            i += 1;
                            continue;
                        }
                    }
                }
                if from != to_c {
                    break;
                }
                i += 1;
            }
            for _ in i..base_components.len() {
                ret.push("..");
            }
            for comp in target_components.iter().skip(i) {
                ret.push(comp);
            }
            ret
        }
    }

    fn to_slash(&self) -> Option<Cow<str>> {
        if std::path::MAIN_SEPARATOR == '/' {
            self.to_str().map(Cow::Borrowed)
        } else {
            self.to_str().map(|s| Cow::Owned(s.replace(std::path::MAIN_SEPARATOR, "/")))
        }
    }

    fn to_slash_lossy(&self) -> Cow<str> {
        if std::path::MAIN_SEPARATOR == '/' {
            self.to_string_lossy()
        } else {
            Cow::Owned(self.to_string_lossy().replace(std::path::MAIN_SEPARATOR, "/"))
        }
    }

    fn as_path(&self) -> &Path {
        self
    }
}

impl<T: Deref<Target = str>> SugarPath for T {
    fn normalize(&self) -> PathBuf {
        self.as_path().normalize()
    }
    fn absolutize(&self) -> PathBuf {
        self.as_path().absolutize()
    }
    fn absolutize_with<'a>(&self, base: impl IntoCowPath<'a>) -> PathBuf {
        self.as_path().absolutize_with(base)
    }
    fn relative(&self, to: impl AsRef<Path>) -> PathBuf {
        self.as_path().relative(to)
    }
    fn to_slash(&self) -> Option<Cow<str>> {
        self.as_path().to_slash()
    }
    fn to_slash_lossy(&self) -> Cow<str> {
        self.as_path().to_slash_lossy()
    }
    fn as_path(&self) -> &Path {
        Path::new(self.deref())
    }
}

