use std::fmt;
use std::iter::FromIterator;

#[derive(Clone, Copy, Debug, PartialEq, Default)]
pub struct StatsBuilder {
    count: usize,
    mean: f64,
    m2: f64,
}

impl StatsBuilder {
    pub fn update(&mut self, x: f64) {
        self.count += 1;
        let delta1 = x - self.mean;
        self.mean += delta1 / self.count as f64;
        let delta2 = x - self.mean;
        self.m2 += delta1 * delta2;
    }
}

impl Extend<f64> for StatsBuilder {
    fn extend<T: IntoIterator<Item = f64>>(&mut self, iter: T) {
        for x in iter {
            self.update(x);
        }
    }
}

#[derive(Clone, Copy, Debug, PartialEq)]
pub struct SampleStats {
    pub count: usize,
    pub mean: f64,
    pub var: f64,
}

impl From<StatsBuilder> for SampleStats {
    fn from(b: StatsBuilder) -> SampleStats {
        SampleStats {
            count: b.count,
            mean: if b.count == 0 { f64::NAN } else { b.mean },
            var: if b.count <= 1 { f64::NAN } else { b.m2 / (b.count - 1) as f64 },
        }
    }
}

impl FromIterator<f64> for SampleStats {
    fn from_iter<T: IntoIterator<Item = f64>>(iter: T) -> SampleStats {
        let mut b = StatsBuilder::default();
        b.extend(iter);
        b.into()
    }
}

impl SampleStats {
    pub fn mean_var(self) -> f64 {
        self.var / self.count as f64
    }
}

#[derive(Clone, PartialEq, Debug, Copy)]
pub struct ConfidenceInterval {
    pub center: f64,
    pub radius: f64,
    pub sig_level: f64,
}

impl fmt::Display for ConfidenceInterval {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        let prec = f.precision().unwrap_or(2);
        write!(f, "{:+.prec$} ± {:.prec$} (p={}%)", self.center, self.radius, self.sig_level * 100.0)
    }
}

#[derive(Debug, Clone, Copy)]
pub enum Error {
    BadSigLevel,
    NotEnoughData,
    InfiniteVariance,
    ZeroVariance,
}

pub fn difference_of_means(sig_level: f64, x: SampleStats, y: SampleStats) -> Result<ConfidenceInterval, Error> {
    if sig_level <= 0.0 || sig_level >= 1.0 { return Err(Error::BadSigLevel); }
    if x.count < 2 || y.count < 2 { return Err(Error::NotEnoughData); }
    if !x.var.is_finite() || !y.var.is_finite() { return Err(Error::InfiniteVariance); }
    if x.var == 0.0 || y.var == 0.0 { return Err(Error::ZeroVariance); }
    let alpha = 1.0 - sig_level;
    let p = 1.0 - (alpha / 2.0);
    let x_mean_var = x.mean_var();
    let y_mean_var = y.mean_var();
    let var_delta = x_mean_var + y_mean_var;
    let k_x = x_mean_var * x_mean_var / (x.count - 1) as f64;
    let k_y = y_mean_var * y_mean_var / (y.count - 1) as f64;
    let v = var_delta * (var_delta / (k_x + k_y));
    let t = student_t::inv_cdf(p, v);
    Ok(ConfidenceInterval { center: y.mean - x.mean, radius: t * var_delta.sqrt(), sig_level })
}

mod student_t {
    use special::Beta;
    pub fn inv_cdf(p: f64, dof: f64) -> f64 {
        let x = 2.0 * p.min(1.0 - p);
        let a = 0.5 * dof;
        let b = 0.5;
        let y = x.inv_inc_beta(a, b, a.ln_beta(b));
        let y = (dof * (1.0 - y) / y).sqrt();
        if p > 0.5 { y } else { -y }
    }
}

