use std::path::{Path, PathBuf};
use url::Url;
use thiserror::Error;
use deno_error::JsError;

#[derive(Debug, Error, JsError)]
#[class(uri)]
#[error("Could not convert path to URL.\n  Path: {0}")]
pub struct PathToUrlError(pub PathBuf);

pub fn resolve_path(path_str: &str, current_dir: &Path) -> Result<Url, PathToUrlError> {
    let path = current_dir.join(path_str);
    let path = normalize_path(path);
    url_from_file_path(&path)
}

pub fn normalize_path<P: AsRef<Path>>(path: P) -> PathBuf {
    fn inner(p: &Path) -> PathBuf {
        let mut components = p.components().peekable();
        let mut ret = if let Some(c @ std::path::Component::Prefix(_)) = components.peek().cloned() {
            components.next();
            PathBuf::from(c.as_os_str())
        } else {
            PathBuf::new()
        };
        for component in components {
            match component {
                std::path::Component::Prefix(_) => unreachable!(),
                std::path::Component::RootDir => ret.push(component.as_os_str()),
                std::path::Component::CurDir => {},
                std::path::Component::ParentDir => { ret.pop(); },
                std::path::Component::Normal(c) => { ret.push(c); },
            }
        }
        ret
    }
    inner(path.as_ref())
}

pub fn url_from_file_path(path: &Path) -> Result<Url, PathToUrlError> {
    #[cfg(any(unix, windows, target_os = "redox", target_os = "wasi"))]
    {
        Url::from_file_path(path).map_err(|()| PathToUrlError(path.to_path_buf()))
    }
    #[cfg(not(any(unix, windows, target_os = "redox", target_os = "wasi")))]
    {
        url_from_file_path_wasm(path).map_err(|()| PathToUrlError(path.to_path_buf()))
    }
}

fn url_from_file_path_wasm(_path: &Path) -> Result<Url, ()> {
    Ok(Url::parse("file://").unwrap())
}

