use quinn::{ConnectError, ConnectionError, WriteError};
use thiserror::Error;

#[derive(Error, Debug, PartialEq)]
pub enum QuicError {
    #[error(transparent)]
    Connect(#[from] ConnectError),
    #[error(transparent)]
    Connection(#[from] ConnectionError),
    #[error(transparent)]
    StreamWrite(#[from] WriteError),
    #[error("Handshake timeout")]
    HandshakeTimeout,
}

pub fn record_error(err: QuicError, stats: &SendTransactionStats) {
    match err {
        QuicError::Connect(ConnectError::EndpointStopping) => {
            stats.connect_error_other.fetch_add(1, Ordering::Relaxed);
        }
        QuicError::Connect(ConnectError::CidsExhausted) => {
            stats.connect_error_cids_exhausted.fetch_add(1, Ordering::Relaxed);
        }
        QuicError::Connect(ConnectError::InvalidRemoteAddress(_)) => {
            stats.connect_error_invalid_remote_address.fetch_add(1, Ordering::Relaxed);
        }
        QuicError::Connection(ConnectionError::ApplicationClosed(_)) => {
            stats.connection_error_application_closed.fetch_add(1, Ordering::Relaxed);
        }
        QuicError::Connection(ConnectionError::TimedOut) => {
            stats.connection_error_timed_out.fetch_add(1, Ordering::Relaxed);
        }
        QuicError::StreamWrite(WriteError::ClosedStream) => {
            stats.write_error_closed_stream.fetch_add(1, Ordering::Relaxed);
        }
        QuicError::HandshakeTimeout => {
            stats.connection_error_timed_out.fetch_add(1, Ordering::Relaxed);
        }
        _ => {}
    }
}

