pub enum Query {
    Simple(String, String),
    Regex(regex::Regex, String),
    PreserveCase(String, String),
}
impl Query {
    pub fn simple(old: &str, new: &str) -> Self { Self::Simple(old.to_string(), new.to_string()) }
    pub fn regex(re: regex::Regex, repl: &str) -> Self { Self::Regex(re, repl.to_string()) }
    pub fn preserve_case(pat: &str, repl: &str) -> Self { Self::PreserveCase(pat.to_string(), repl.to_string()) }
}

pub fn replace<'a>(input: &'a str, query: &Query) -> Option<Replacement<'a>> {
    let fragments = get_fragments(input, query);
    if fragments.is_empty() { return None; }
    let output = get_output(input, &fragments);
    Some(Replacement { fragments, input, output })
}

pub struct Replacement<'a> {
    fragments: Fragments,
    input: &'a str,
    output: String,
}
impl<'a> Replacement<'a> {
    pub fn output(&self) -> &str { &self.output }
}

pub struct Fragments(Vec<(Fragment, Fragment)>);
pub struct Fragment { pub index: usize, pub text: String }

fn get_fragments(input: &str, query: &Query) -> Fragments {
    match query {
        Query::PreserveCase(pat, repl) => {
            let items = vec![
                (to_snake_case(pat), to_snake_case(repl)),
                (to_camel_case(pat), to_camel_case(repl)),
                (to_pascal_case(pat), to_pascal_case(repl)),
                (to_kebab_case(pat), to_kebab_case(repl)),
                (to_screaming_snake_case(pat), to_screaming_snake_case(repl)),
                (to_train_case(pat), to_train_case(repl)),
            ];
            let mut best = None;
            let mut best_idx = input.len();
            for (i, (p, _)) in items.iter().enumerate() {
                if let Some(pos) = input.find(p) {
                    if pos < best_idx { best_idx = pos; best = Some(i); }
                }
            }
            if let Some(i) = best {
                let (p, r) = &items[i];
                let mut frags = Fragments(Vec::new());
                frags.0.push((Fragment { index: best_idx, text: p.clone() }, Fragment { index: best_idx, text: r.clone() }));
                frags
            } else {
                Fragments(Vec::new())
            }
        }
        _ => Fragments(Vec::new()),
    }
}

fn get_output(input: &str, fragments: &Fragments) -> String {
    let mut out = String::new();
    let mut last = 0;
    for (inp, outp) in &fragments.0 {
        out.push_str(&input[last..inp.index]);
        out.push_str(&outp.text);
        last = inp.index + inp.text.len();
    }
    out.push_str(&input[last..]);
    out
}

