fn to_pascal_case(s: &str) -> String { inflector::cases::pascalcase::to_pascal_case(s) }
fn to_kebab_case(s: &str) -> String { inflector::cases::kebabcase::to_kebab_case(s) }
fn to_screaming_snake_case(s: &str) -> String { inflector::cases::screamingsnakecase::to_screaming_snake_case(s) }
