pub struct Receiver<T> {
    rx: mpsc::Receiver<T>,
    ctl: ReceiverCtl,
}

pub enum SendError<T> {
    Io(std::io::Error),
    Disconnected(T),
}

pub enum TrySendError<T> {
    Io(std::io::Error),
    Full(T),
    Disconnected(T),
}

struct SenderCtl {
    inner: Arc<Inner>,
}

struct ReceiverCtl {
    registration: LazyCell<Registration>,
    inner: Arc<Inner>,
}

struct Inner {
    pending: AtomicUsize,
    senders: AtomicUsize,
    set_readiness: AtomicLazyCell<SetReadiness>,
}

pub fn channel<T>() -> (Sender<T>, Receiver<T>) {
    let (tx_ctl, rx_ctl) = ctl_pair();
    let (tx, rx) = mpsc::channel();
    (
        Sender { tx, ctl: tx_ctl },
        Receiver { rx, ctl: rx_ctl },
    )
}

fn ctl_pair() -> (SenderCtl, ReceiverCtl) {
    let inner = Arc::new(Inner {
        pending: AtomicUsize::new(0),
        senders: AtomicUsize::new(1),
        set_readiness: AtomicLazyCell::new(),
    });
    (
        SenderCtl { inner: inner.clone() },
        ReceiverCtl { registration: LazyCell::new(), inner },
    )
}

