pub struct Timer<T> {
    tick_ms: u64,
    entries: slab::Slab<Entry<T>>, // placeholder, assume compatible
    wheel: Vec<WheelEntry>,
    start: Instant,
    tick: u64,
    next: Token,
    mask: u64,
    inner: LazyCell<Inner>,
}

pub struct Builder {
    tick: Duration,
    num_slots: usize,
    capacity: usize,
}

pub struct Timeout {
    token: Token,
    tick: u64,
}

type Result<T> = std::result::Result<T, TimerError>;

#[derive(Debug)]
pub struct TimerError {
    kind: TimerErrorKind,
    desc: &'static str,
}

#[derive(Debug)]
pub enum TimerErrorKind {
    TimerOverflow,
}

impl std::fmt::Display for TimerError {
    fn fmt(&self, f: &mut std::fmt::Formatter) -> std::fmt::Result {
        write!(f, "{}: {}", self.kind, self.desc)
    }
}

impl std::error::Error for TimerError {
    fn description(&self) -> &str { self.desc }
}

impl TimerError {
    fn overflow() -> TimerError {
        TimerError { kind: TimerErrorKind::TimerOverflow, desc: "too many timer entries" }
    }
}

impl Default for Builder {
    fn default() -> Builder {
        Builder { tick: Duration::from_millis(100), num_slots: 256, capacity: 65_536 }
    }
}

impl Builder {
    pub fn tick_duration(mut self, d: Duration) -> Builder { self.tick = d; self }
    pub fn num_slots(mut self, n: usize) -> Builder { self.num_slots = n; self }
    pub fn capacity(mut self, c: usize) -> Builder { self.capacity = c; self }
    pub fn build<T>(self) -> Timer<T> { Timer::new(self.tick, self.num_slots, self.capacity, Instant::now()) }
}

impl<T> Timer<T> {
    fn new(tick: Duration, num_slots: usize, capacity: usize, start: Instant) -> Timer<T> {
        let tick_ms = tick.as_millis() as u64;
        let num_slots = num_slots.next_power_of_two();
        let mask = (num_slots as u64) - 1;
        let wheel = vec![WheelEntry { next_tick: u64::MAX, head: Token(usize::MAX) }; num_slots];
        Timer { tick_ms, entries: slab::Slab::with_capacity(capacity), wheel, start, tick: 0, next: Token(usize::MAX), mask, inner: LazyCell::new() }
    }
    pub fn set_timeout(&mut self, delay: Duration, state: T) -> Result<Timeout> {
        let delay_from_start = self.start.elapsed() + delay;
        self.set_timeout_at(delay_from_start, state)
    }
    fn set_timeout_at(&mut self, delay: Duration, state: T) -> Result<Timeout> {
        let mut tick = (delay.as_millis() as u64 + self.tick_ms / 2) / self.tick_ms;
        if tick <= self.tick { tick = self.tick + 1; }
        // insertion logic omitted for brevity, assume success
        Ok(Timeout { token: Token(0), tick })
    }
    pub fn poll(&mut self) -> Option<T> { None }
}

