pub struct RawTbl {
    pub cols: Vec<RawCol>,
}

impl RawTbl {
    pub fn read<R: Read>(r: R) -> Result<Self> {
        let mut csv_reader = Reader::from_reader(r);
        let mut cols = Vec::new();
        for header in csv_reader.headers()? {
            cols.push(RawCol { header: header.to_string(), cells: Vec::new() });
        }
        if cols.is_empty() {
            anyhow::bail!("empty table");
        }
        for record in csv_reader.records() {
            let record = record?;
            let mut cells = record.iter();
            for col in cols.iter_mut() {
                let cell = cells.next();
                col.cells.push(
                    cell.filter(|s| s.chars().any(|c| !c.is_whitespace()))
                        .map(|s| s.to_string()),
                );
            }
        }
        Ok(RawTbl { cols })
    }
}

