use std::io::Write;

const END: u8 = 0xC0;
const ESC: u8 = 0xDB;
const ESC_END: u8 = 0xDC;
const ESC_ESC: u8 = 0xDD;

#[derive(Debug)]
pub struct SlipEncoder {
    begin_with_end: bool,
}

impl SlipEncoder {
    pub fn new(begin_with_end: bool) -> Self {
        Self { begin_with_end }
    }

    pub fn encode(&mut self, buf: &[u8], sink: &mut dyn Write) -> std::io::Result<usize> {
        let mut len = if self.begin_with_end { sink.write(&[END])? } else { 0 };
        for &b in buf {
            match b {
                END => {
                    len += sink.write(&[ESC, ESC_END])?;
                }
                ESC => {
                    len += sink.write(&[ESC, ESC_ESC])?;
                }
                _ => {
                    len += sink.write(&[b])?;
                }
            }
        }
        len += sink.write(&[END])?;
        sink.flush()?;
        Ok(len)
    }
}

impl Default for SlipEncoder {
    fn default() -> Self {
        Self::new(true)
    }
}

