use std::io::{Read, Write};

const END: u8 = 0xC0;
const ESC: u8 = 0xDB;
const ESC_END: u8 = 0xDC;
const ESC_ESC: u8 = 0xDD;

#[derive(Debug)]
enum State {
    Normal,
    Error,
    Escape,
}

#[derive(Debug)]
pub struct SlipDecoder {
    count: usize,
    state: State,
}

impl SlipDecoder {
    pub fn new() -> Self {
        Self {
            count: 0,
            state: State::Normal,
        }
    }

    pub fn decode(&mut self, source: &mut dyn Read, sink: &mut dyn Write) -> Result<usize, SlipError> {
        for value in source.bytes() {
            let v = value?;
            match self.state {
                State::Normal => match v {
                    END => {
                        if self.count > 0 {
                            let len = self.count;
                            self.count = 0;
                            return Ok(len);
                        }
                    }
                    ESC => {
                        self.state = State::Escape;
                    }
                    _ => {
                        self.push(sink, v)?;
                    }
                },
                State::Error => {
                    if v == END {
                        self.count = 0;
                        self.state = State::Normal;
                    }
                }
                State::Escape => match v {
                    ESC_END => {
                        self.push(sink, END)?;
                        self.state = State::Normal;
                    }
                    ESC_ESC => {
                        self.push(sink, ESC)?;
                        self.state = State::Normal;
                    }
                    _ => {
                        self.state = State::Error;
                        return Err(SlipError::FramingError);
                    }
                },
            }
        }
        Err(SlipError::EndOfStream)
    }

    fn push(&mut self, sink: &mut dyn Write, value: u8) -> Result<usize, SlipError> {
        match sink.write(&[value]) {
            Ok(1) => {
                self.count += 1;
                Ok(1)
            }
            Ok(_) => Err(SlipError::OversizedPacket),
            Err(e) => Err(SlipError::ReadError(e)),
        }
    }
}

impl Default for SlipDecoder {
    fn default() -> Self {
        Self::new()
    }
}

#[derive(Debug)]
pub enum SlipError {
    FramingError,
    OversizedPacket,
    EndOfStream,
    ReadError(std::io::Error),
}

impl From<std::io::Error> for SlipError {
    fn from(e: std::io::Error) -> Self {
        SlipError::ReadError(e)
    }
}

