use core::{fmt, isize, str};

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ParseHexfError {
    kind: ParseHexfErrorKind,
}

#[derive(Debug, Clone, PartialEq, Eq)]
enum ParseHexfErrorKind {
    Empty,
    Invalid,
    Inexact,
}

const EMPTY: ParseHexfError = ParseHexfError { kind: ParseHexfErrorKind::Empty };
const INVALID: ParseHexfError = ParseHexfError { kind: ParseHexfErrorKind::Invalid };
const INEXACT: ParseHexfError = ParseHexfError { kind: ParseHexfErrorKind::Inexact };

impl fmt::Display for ParseHexfError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self.kind {
            ParseHexfErrorKind::Empty => write!(f, "cannot parse float from empty string"),
            ParseHexfErrorKind::Invalid => write!(f, "invalid hexadecimal float literal"),
            ParseHexfErrorKind::Inexact => write!(f, "cannot exactly represent float in target type"),
        }
    }
}

fn parse(s: &[u8], allow_underscore: bool) -> Result<(bool, u64, isize), ParseHexfError> {
    let (s, negative) = match s.split_first() {
        Some((&b'+', s)) => (s, false),
        Some((&b'-', s)) => (s, true),
        Some(_) => (s, false),
        None => return Err(EMPTY),
    };
    if !(s.starts_with(b"0x") || s.starts_with(b"0X")) { return Err(INVALID); }
    let mut s = &s[2..];
    let mut acc: u64 = 0;
    let mut digit_seen = false;
    loop {
        let (s_, digit) = match s.split_first() {
            Some((&c @ b'0'..=b'9', s)) => (s, c - b'0'),
            Some((&c @ b'a'..=b'f', s)) => (s, c - b'a' + 10),
            Some((&c @ b'A'..=b'F', s)) => (s, c - b'A' + 10),
            Some((&b'_', s_)) if allow_underscore && digit_seen => { s = s_; continue; },
            _ => break,
        };
        s = s_;
        digit_seen = true;
        if acc >> 60 != 0 { return Err(INEXACT); }
        acc = (acc << 4) | digit as u64;
    }
    let mut nfracs: isize = 0;
    let mut nzeroes: isize = 0;
    let mut frac_digit_seen = false;
    if s.starts_with(b".") {
        s = &s[1..];
        loop {
            let (s_, digit) = match s.split_first() {
                Some((&c @ b'0'..=b'9', s)) => (s, c - b'0'),
                Some((&c @ b'a'..=b'f', s)) => (s, c - b'a' + 10),
                Some((&c @ b'A'..=b'F', s)) => (s, c - b'A' + 10),
                Some((&b'_', s_)) if allow_underscore && frac_digit_seen => { s = s_; continue; },
                _ => break,
            };
            s = s_;
            frac_digit_seen = true;
            if digit == 0 {
                nzeroes = nzeroes.checked_add(1).ok_or(INEXACT)?;
            } else {
                let nnewdigits = nzeroes.checked_add(1).ok_or(INEXACT)?;
                nfracs = nfracs.checked_add(nnewdigits).ok_or(INEXACT)?;
                nzeroes = 0;
                if acc != 0 {
                    if nnewdigits >= 16 || acc >> (64 - nnewdigits * 4) != 0 { return Err(INEXACT); }
                    acc = acc << (nnewdigits * 4);
                }
                acc |= digit as u64;
            }
        }
    }
    if !(digit_seen || frac_digit_seen) { return Err(INVALID); }
    let s = match s.split_first() { Some((&b'P', s)) | Some((&b'p', s)) => s, _ => return Err(INVALID) };
    let (mut s, negative_exponent) = match s.split_first() {
        Some((&b'+', s)) => (s, false),
        Some((&b'-', s)) => (s, true),
        Some(_) => (s, false),
        None => return Err(INVALID),
    };
    let mut digit_seen = false;
    let mut exponent: isize = 0;
    loop {
        let (s_, digit) = match s.split_first() {
            Some((&c @ b'0'..=b'9', s)) => (s, c - b'0'),
            Some((&b'_', s_)) if allow_underscore => { s = s_; continue; },
            None if digit_seen => break,
            _ => return Err(INVALID),
        };
        s = s_;
        digit_seen = true;
        if acc != 0 {
            exponent = exponent.checked_mul(10).and_then(|v| v.checked_add(digit as isize)).ok_or(INEXACT)?;
        }
    }
    if negative_exponent { exponent = -exponent; }
    if acc == 0 { return Ok((negative, 0, 0)); }
    let exponent = nfracs.checked_mul(4).and_then(|v| exponent.checked_sub(v)).ok_or(INEXACT)?;
    Ok((negative, acc, exponent))
}

macro_rules! define_convert {
    ($name:ident => $f:ident) => {
        fn $name(negative: bool, mantissa: u64, exponent: isize) -> Result<$f, ParseHexfError> {
            if exponent < -0xffff || exponent > 0xffff { return Err(INEXACT); }
            let trailing = mantissa.trailing_zeros() & 63;
            let mantissa = mantissa >> trailing;
            let exponent = exponent + trailing as isize;
            let leading = mantissa.leading_zeros();
            let normalexp = exponent + (63 - leading as isize);
            let mantissasize = if normalexp < $f::MIN_EXP as isize - $f::MANTISSA_DIGITS as isize {
                return Err(INEXACT);
            } else if normalexp < ($f::MIN_EXP - 1) as isize {
                $f::MANTISSA_DIGITS as isize - $f::MIN_EXP as isize + normalexp + 1
            } else if normalexp < $f::MAX_EXP as isize {
                $f::MANTISSA_DIGITS as isize
            } else {
                return Err(INEXACT);
            };
            if mantissa >> mantissasize == 0 {
                let mut mant = mantissa as $f;
                if negative { mant = -mant; }
                Ok(mant * libm::exp2(exponent as f64) as $f)
            } else {
                Err(INEXACT)
            }
        }
    };
}

