use tree_hash::{MerkleHasher, Hash256, HASHSIZE};
use ethereum_hashing::hash_fixed;

pub fn merkle_root(bytes: &[u8], minimum_leaf_count: usize) -> Hash256 {
    let leaves = std::cmp::max(bytes.len().div_ceil(HASHSIZE), minimum_leaf_count);
    if leaves == 0 {
        Hash256::ZERO
    } else if leaves == 1 {
        let mut hash = [0; HASHSIZE];
        hash[0..bytes.len()].copy_from_slice(bytes);
        Hash256::from_slice(&hash)
    } else if leaves == 2 {
        let mut leaves_arr = [0; HASHSIZE * 2];
        leaves_arr[0..bytes.len()].copy_from_slice(bytes);
        Hash256::from_slice(&hash_fixed(&leaves_arr))
    } else {
        let mut hasher = MerkleHasher::with_leaves(leaves);
        hasher.write(bytes).expect("write");
        hasher.finish().expect("finish")
    }
}

