    pub fn new(src: Source, start: usize, end: usize, source_id: Option<u32>) -> Option<Self> {
        if src.text.get(start..end).is_some() {
            Some(Self { src, start, end, source_id })
        } else {
            None
        }
    }

    pub fn start_line_col_one_index(&self) -> LineCol {
        let line = self.src.text[..self.start].matches('\n').count() + 1;
        let col = self.start - self.src.text[..self.start].rfind('\n').map_or(0, |p| p + 1) + 1;
        LineCol { line, col }
    }
}

