fn find_camel_case_word_boundary(name: &str) -> Option<usize> {
    let mut prev_lower = false;
    for (i, c) in name.char_indices() {
        if c.is_uppercase() && prev_lower {
            return Some(i);
        }
        prev_lower = c.is_lowercase();
    }
    None
}

fn camel_case_split_words(mut name: &str) -> impl Iterator<Item = &str> {
    std::iter::from_fn(move || {
        if name.is_empty() {
            return None;
        }
        let idx = find_camel_case_word_boundary(name).unwrap_or(name.len());
        let word = &name[..idx];
        name = &name[idx..];
        Some(word)
    })
}

fn split_words(name: &str) -> impl Iterator<Item = &str> {
    name.split('_').flat_map(camel_case_split_words)
}

pub fn to_snake_case(name: &str) -> String {
    let mut ret = String::with_capacity(name.len());
    let (leading, trimmed) = name.split_at(name.find(|c| c != '_').unwrap_or(name.len()));
    ret.push_str(leading);
    let mut words = split_words(trimmed);
    if let Some(first) = words.next() {
        ret.extend(first.chars().flat_map(char::to_lowercase));
        for w in words {
            ret.push('_');
            ret.extend(w.chars().flat_map(char::to_lowercase));
        }
    }
    ret
}

