use std::path::PathBuf;
use std::io::Read;
use std::fs::File;
use std::io::BufReader;
use byteorder::{LittleEndian, ReadBytesExt};
use rubato::Resampler;
use rustfft::{num_complex::Complex, FftPlanner};

pub struct Vec3 { pub x: f32, pub y: f32, pub z: f32 }

pub struct HrirPoint { pub pos: Vec3, pub left_hrir: Vec<f32>, pub right_hrir: Vec<f32> }

pub struct Face { pub a: usize, pub b: usize, pub c: usize }

pub struct HrtfError;
impl From<std::io::Error> for HrtfError { fn from(_: std::io::Error) -> Self { HrtfError } }

pub struct HrirSphere {
    length: usize,
    points: Vec<HrirPoint>,
    faces: Vec<Face>,
    source: PathBuf,
}

impl HrirSphere {
    pub fn from_file<P: AsRef<std::path::Path>>(path: P, device_sample_rate: u32) -> Result<Self, HrtfError> {
        let mut sphere = Self::new(BufReader::new(File::open(path.as_ref())?), device_sample_rate)?;
        sphere.source = path.as_ref().to_owned();
        Ok(sphere)
    }
    fn new<R: Read>(mut reader: R, _device_sample_rate: u32) -> Result<Self, HrtfError> {
        let mut magic = [0; 4];
        reader.read_exact(&mut magic)?;
        let _sample_rate = reader.read_u32::<LittleEndian>()?;
        let length = reader.read_u32::<LittleEndian>()? as usize;
        let vertex_count = reader.read_u32::<LittleEndian>()? as usize;
        let index_count = reader.read_u32::<LittleEndian>()? as usize;
        let faces = read_faces(&mut reader, index_count)?;
        let mut points = Vec::with_capacity(vertex_count);
        for _ in 0..vertex_count {
            let x = reader.read_f32::<LittleEndian>()?;
            let y = reader.read_f32::<LittleEndian>()?;
            let z = reader.read_f32::<LittleEndian>()?;
            let left_hrir = read_hrir(&mut reader, length)?;
            let right_hrir = read_hrir(&mut reader, length)?;
            points.push(HrirPoint { pos: Vec3 { x, y, z }, left_hrir, right_hrir });
        }
        Ok(Self { length, points, faces, source: PathBuf::new() })
    }
    pub fn points(&self) -> &[HrirPoint] { &self.points }
}

fn read_faces<R: Read>(reader: &mut R, index_count: usize) -> Result<Vec<Face>, HrtfError> {
    let mut indices = Vec::with_capacity(index_count);
    for _ in 0..index_count {
        indices.push(reader.read_u32::<LittleEndian>()?);
    }
    Ok(indices.chunks(3).map(|c| Face { a: c[0] as usize, b: c[1] as usize, c: c[2] as usize }).collect())
}

fn read_hrir<R: Read>(reader: &mut R, len: usize) -> Result<Vec<f32>, HrtfError> {
    let mut v = Vec::with_capacity(len);
    for _ in 0..len {
        v.push(reader.read_f32::<LittleEndian>()?);
    }
    Ok(v)
}

