use std::fmt;
use once_cell::sync::Lazy;
use url::Url;
use serde::{Serialize, Deserialize};

// Minimal error type with only the variants used in the parsing logic
#[derive(Debug)]
pub enum Error {
    InvalidNameVersionSegment,
    InvalidGroupName(String),
    InvalidPackageName(String),
    InvalidPackageVersion(String),
    UrlParseError(url::ParseError),
}

impl std::error::Error for Error {}
impl fmt::Display for Error {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Error::InvalidNameVersionSegment => write!(f, "invalid name/version segment"),
            Error::InvalidGroupName(s) => write!(f, "invalid group name: {}", s),
            Error::InvalidPackageName(s) => write!(f, "invalid package name: {}", s),
            Error::InvalidPackageVersion(s) => write!(f, "invalid package version: {}", s),
            Error::UrlParseError(e) => write!(f, "url parse error: {}", e),
        }
    }
}

// Simple newtype wrappers used by the crate
#[derive(Clone, Debug, PartialEq, Eq, PartialOrd, Ord, Serialize, Deserialize)]
pub struct Registry(Url);
impl Registry {
    fn try_from_segments(_segments: &[&str]) -> Option<Self> {
        None
    }
}
impl Default for Registry {
    fn default() -> Self {
        Registry(Url::parse("https://packages.fluvio.io/v1/").unwrap())
    }
}
impl fmt::Display for Registry {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        self.0.fmt(f)
    }
}

#[derive(Clone, Debug, PartialEq, Eq, PartialOrd, Ord, Serialize, Deserialize)]
pub struct GroupName(String);
impl std::str::FromStr for GroupName {
    type Err = Error;
    fn from_str(s: &str) -> Result<Self, Self::Err> {
        if s.contains('/') || s.contains(':') {
            return Err(Error::InvalidGroupName(s.to_string()));
        }
        Ok(GroupName(s.to_string()))
    }
}
impl fmt::Display for GroupName {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        self.0.fmt(f)
    }
}

#[derive(Clone, Debug, PartialEq, Eq, PartialOrd, Ord, Serialize, Deserialize)]
pub struct PackageName(String);
impl std::str::FromStr for PackageName {
    type Err = Error;
    fn from_str(s: &str) -> Result<Self, Self::Err> {
        if s.contains('/') || s.contains(':') {
            return Err(Error::InvalidPackageName(s.to_string()));
        }
        Ok(PackageName(s.to_string()))
    }
}
impl fmt::Display for PackageName {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        self.0.fmt(f)
    }
}

// PackageVersion enum used by the parser
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum PackageVersion {
    Semver(semver::Version),
    Tag(String),
}
impl std::str::FromStr for PackageVersion {
    type Err = Error;
    fn from_str(s: &str) -> Result<Self, Self::Err> {
        if let Ok(v) = semver::Version::parse(s) {
            return Ok(PackageVersion::Semver(v));
        }
        // For simplicity treat any non‑semver as a tag
        Ok(PackageVersion::Tag(s.to_string()))
    }
}

pub type WithVersion = PackageVersion;
pub type MaybeVersion = Option<PackageVersion>;

pub struct PackageId<V = MaybeVersion> {
    registry: Option<Registry>,
    group: Option<GroupName>,
    name: PackageName,
    version: V,
}

impl std::str::FromStr for PackageId<WithVersion> {
    type Err = Error;
    fn from_str(s: &str) -> Result<Self, Self::Err> {
        let mut segments: Vec<&str> = s.split('/').collect();
        let name_version = segments.pop().ok_or(Error::InvalidNameVersionSegment)?;
        let mut parts = name_version.split(':');
        let name_str = parts.next().ok_or(Error::InvalidNameVersionSegment)?;
        let version_str = parts.next().ok_or(Error::InvalidNameVersionSegment)?;
        let version = version_str.parse::<PackageVersion>()?;
        let name = name_str.parse::<PackageName>()?;
        let maybe_group = segments.pop();
        let group = match maybe_group {
            None | Some("fluvio") => None,
            Some(g) => Some(g.parse()?),
        };
        let registry = Registry::try_from_segments(&segments);
        Ok(PackageId {
            registry,
            group,
            name,
            version,
        })
    }
}

