pub fn eytzinger_search_by<'a, T: 'a, F>(data: &'a [T], mut f: F) -> Option<usize>
where F: FnMut(&'a T) -> std::cmp::Ordering {
    let mut i = 0usize;
    loop {
        match data.get(i) {
            Some(v) => match f(v) {
                std::cmp::Ordering::Equal => return Some(i),
                o => {
                    let o = (o as usize >> 1) & 1;
                    i = 2 * i + 1 + o;
                }
            },
            None => return None,
        }
    }
}

