pub struct PriceConf {
    pub price: i64,
    pub conf: u64,
    pub expo: i32,
}

impl PriceConf {
    pub fn scale_to_exponent(&self, target_expo: i32) -> Option<PriceConf> {
        let mut delta = target_expo.checked_sub(self.expo)?;
        if delta >= 0 {
            let mut p = self.price;
            let mut c = self.conf;
            while delta > 0 && (p != 0 || c != 0) {
                p = p.checked_div(10)?;
                c = c.checked_div(10)?;
                delta = delta.checked_sub(1)?;
            }
            Some(PriceConf { price: p, conf: c, expo: target_expo })
        } else {
            let mut p = self.price;
            let mut c = self.conf;
            while delta < 0 {
                p = p.checked_mul(10)?;
                c = c.checked_mul(10)?;
                delta = delta.checked_add(1)?;
            }
            Some(PriceConf { price: p, conf: c, expo: target_expo })
        }
    }
}

