use ::gf::poly::Polynom;
use core::ops::{Deref, DerefMut};

pub struct Buffer {
    poly: Polynom,
    data_len: usize,
}

impl Buffer {
    pub fn from_polynom(poly: Polynom, data_len: usize) -> Self {
        Buffer { poly, data_len }
    }
    pub fn from_slice(slice: &[u8], data_len: usize) -> Self {
        Buffer { poly: Polynom::from(slice), data_len }
    }
    pub fn data(&self) -> &[u8] {
        &self[..self.data_len]
    }
    pub fn ecc(&self) -> &[u8] {
        &self[self.data_len..]
    }
    pub fn append(&mut self, rhs: &[u8]) {
        let ofst = self.len();
        self.set_length(ofst + rhs.len());
        for (i, rhs_x) in rhs.iter().enumerate() {
            self[i + ofst] = *rhs_x;
        }
    }
    pub fn len(&self) -> usize {
        self.poly.len()
    }
    pub fn set_length(&mut self, new_len: usize) {
        self.poly.set_length(new_len);
    }
    pub fn iter(&self) -> core::slice::Iter<u8> {
        self.poly.iter()
    }
}

impl Deref for Buffer {
    type Target = Polynom;
    fn deref(&self) -> &Self::Target { &self.poly }
}

impl DerefMut for Buffer {
    fn deref_mut(&mut self) -> &mut Self::Target { &mut self.poly }
}

impl From<Polynom> for Buffer {
    fn from(p: Polynom) -> Buffer {
        Buffer { data_len: p.len(), poly: p }
    }
}

pub struct Encoder {
    generator: Polynom,
}

impl Encoder {
    pub fn new(ecc_len: usize) -> Self {
        Encoder { generator: generator_poly(ecc_len) }
    }
    pub fn encode(&self, data: &[u8]) -> Buffer {
        let mut data_out = Polynom::from(data);
        let data_len = data.len();
        data_out.set_length(data_len + self.generator.len() - 1);
        let gen = self.generator;
        let mut lgen = Polynom::with_length(self.generator.len());
        for (i, gen_i) in gen.iter().enumerate() {
            lgen[i] = ::gf::LOG[*gen_i as usize];
        }
        for i in 0..data_len {
            let coef = data_out[i];
            if coef != 0 {
                let lcoef = ::gf::LOG[coef as usize] as usize;
                for j in 1..gen.len() {
                    data_out[i + j] ^= ::gf::EXP[(lcoef + lgen[j] as usize) % 255];
                }
            }
        }
        data_out[..data_len].copy_from_slice(data);
        Buffer::from_polynom(data_out, data_len)
    }
}

fn generator_poly(ecclen: usize) -> Polynom {
    let mut gen = polynom![1];
    let mut mm = [1, 0];
    for i in 0..ecclen {
        mm[1] = ::gf::pow(2, i as i32);
        gen = gen.mul(&mm);
    }
    gen
}

pub struct Decoder {
    ecc_len: usize,
}

impl Decoder {
    pub fn new(ecc_len: usize) -> Self {
        Decoder { ecc_len }
    }
    pub fn correct(&self, msg: &[u8], erase_pos: Option<&[u8]>) -> core::result::Result<Buffer, ()> {
        // Simplified stub for example purposes
        let buffer = Buffer::from_slice(msg, msg.len() - self.ecc_len);
        Ok(buffer)
    }
    pub fn is_corrupted(&self, msg: &[u8]) -> bool {
        (0..self.ecc_len).any(|x| msg.eval(::gf::pow(2, x as i32)) != 0)
    }
}

