    core::slice::from_raw_parts(rand_words.as_ptr() as *const u8, rand_words.len() * 4)
};

let mut out_state = [0u32; 8];
let in_state = [0u32; 8];
let block1 = [0u32; 8];
let block2 = [0u32; 8];
unsafe {
    syscall::sys_sha_compress(
        &mut out_state as *mut _,
        &in_state as *const _,
