use serde::Serialize;

#[derive(Clone, Debug, Default, Serialize)]
pub struct Route<'a> {
    route: Vec<Component<'a>>,
}

impl<'a> Route<'a> {
    pub fn parent(&self) -> Option<Self> {
        if self.route.is_empty() {
            None
        } else {
            let mut parent = self.route.clone();
            parent.truncate(self.route.len() - 1);
            Some(Self { route: parent })
        }
    }
}

impl<'a> From<Vec<Component<'a>>> for Route<'a> {
    fn from(route: Vec<Component<'a>>) -> Self {
        Self { route }
    }
}

#[derive(Clone, Debug, PartialEq, Serialize)]
pub enum Component<'a> {
    Key(&'a str),
    Index(usize),
}

impl From<usize> for Component<'_> {
    fn from(index: usize) -> Self {
        Component::Index(index)
    }
}

impl<'a> From<&'a str> for Component<'a> {
    fn from(key: &'a str) -> Self {
        Component::Key(key)
    }
}

#[macro_export]
macro_rules! route {
    ($($key:expr),* $(,)?) => {
        $crate::Route::from(vec![$($crate::Component::from($key)),*])
    };
    () => {
        $crate::Route::default()
    };
}

