use tr::Translator;
use std::borrow::Cow;

struct UpperCaseTranslator;

impl Translator for UpperCaseTranslator {
    fn translate<'a>(&'a self, s: &'a str, _ctx: Option<&'a str>) -> Cow<'a, str> {
        s.to_uppercase().into()
    }

    fn ntranslate<'a>(&'a self, n: u64, singular: &'a str, plural: &'a str, _ctx: Option<&'a str>) -> Cow<'a, str> {
        if n == 1 {
            singular.to_uppercase().into()
        } else {
            plural.to_uppercase().into()
        }
    }
}

